### `source/scripts/generate-asset.mjs`

Generates a real, minimal, spec-valid glTF 2.0 asset (embedded base64 buffer) — no hand-typed base64, no external network fetch, so the GLTFLoader call in `poc.ts` is loading a genuine file, not a stub.

```js
import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const OUT = path.resolve(__dirname, '..', 'assets', 'cube.gltf');

// 8 unique cube vertices, unit cube centered at origin
const positions = new Float32Array([
  -1, -1, -1, //0
   1, -1, -1, //1
   1,  1, -1, //2
  -1,  1, -1, //3
  -1, -1,  1, //4
   1, -1,  1, //5
   1,  1,  1, //6
  -1,  1,  1, //7
]);

const indices = new Uint16Array([
  0,1,2, 2,3,0, // back  (z=-1)
  4,6,5, 4,7,6, // front (z=+1)
  0,3,7, 0,7,4, // left  (x=-1)
  1,5,6, 1,6,2, // right (x=+1)
  3,2,6, 3,6,7, // top   (y=+1)
  0,4,5, 0,5,1, // bottom(y=-1)
]);

const posBytes = Buffer.from(positions.buffer, positions.byteOffset, positions.byteLength);
const idxBytes = Buffer.from(indices.buffer, indices.byteOffset, indices.byteLength);
const combined = Buffer.concat([posBytes, idxBytes]);
const base64 = combined.toString('base64');

function minmax(arr, stride, dim) {
  const min = new Array(dim).fill(Infinity);
  const max = new Array(dim).fill(-Infinity);
  for (let i = 0; i < arr.length; i += stride) {
    for (let d = 0; d < dim; d++) {
      min[d] = Math.min(min[d], arr[i + d]);
      max[d] = Math.max(max[d], arr[i + d]);
    }
  }
  return { min, max };
}
const { min, max } = minmax(positions, 3, 3);

const gltf = {
  asset: { version: '2.0', generator: 'agent-university-threejs-capstone/generate-asset.mjs' },
  scene: 0,
  scenes: [{ nodes: [0] }],
  nodes: [{ mesh: 0, name: 'cube-node' }],
  meshes: [{
    name: 'cube-mesh',
    primitives: [{
      attributes: { POSITION: 0 },
      indices: 1,
      material: 0,
      mode: 4, // TRIANGLES
    }],
  }],
  materials: [{
    name: 'cube-material',
    pbrMetallicRoughness: {
      baseColorFactor: [0.95, 0.55, 0.15, 1.0],
      metallicFactor: 0.1,
      roughnessFactor: 0.6,
    },
    doubleSided: true,
  }],
  buffers: [{
    uri: `data:application/octet-stream;base64,${base64}`,
    byteLength: combined.byteLength,
  }],
  bufferViews: [
    { buffer: 0, byteOffset: 0, byteLength: posBytes.byteLength, target: 34962 },
    { buffer: 0, byteOffset: posBytes.byteLength, byteLength: idxBytes.byteLength, target: 34963 },
  ],
  accessors: [
    { bufferView: 0, byteOffset: 0, componentType: 5126, count: positions.length / 3, type: 'VEC3', min, max },
    { bufferView: 1, byteOffset: 0, componentType: 5123, count: indices.length, type: 'SCALAR' },
  ],
};

fs.mkdirSync(path.dirname(OUT), { recursive: true });
fs.writeFileSync(OUT, JSON.stringify(gltf, null, 2));
console.log('wrote', OUT, `(${combined.byteLength} bytes embedded buffer)`);
```

### `source/scripts/serve.mjs`

Zero-dependency static server (no `serve`/`http-server` package) so the bundled scene + generated glTF are served over real HTTP (GLTFLoader's `fetch` needs an http(s) origin, not `file://`).

```js
import http from 'node:http';
import { readFile } from 'node:fs/promises';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.resolve(__dirname, '..');

const ROUTES = [
  { prefix: '/dist', dir: path.join(ROOT, 'dist') },
  { prefix: '/assets', dir: path.join(ROOT, 'assets') },
  { prefix: '/', dir: path.join(ROOT, 'public') },
];

const MIME = {
  '.html': 'text/html',
  '.js': 'application/javascript',
  '.gltf': 'model/gltf+json',
  '.bin': 'application/octet-stream',
};

const server = http.createServer(async (req, res) => {
  try {
    const url = new URL(req.url, 'http://localhost');
    const pathname = decodeURIComponent(url.pathname);
    let filePath = null;

    for (const route of ROUTES) {
      if (pathname.startsWith(route.prefix)) {
        let rel = pathname.slice(route.prefix.length);
        if (!rel || rel === '/') rel = '/index.html';
        filePath = path.join(route.dir, rel);
        break;
      }
    }
    if (!filePath) { res.writeHead(404); res.end('not found'); return; }

    const data = await readFile(filePath);
    const ext = path.extname(filePath);
    res.writeHead(200, { 'Content-Type': MIME[ext] ?? 'application/octet-stream' });
    res.end(data);
  } catch (e) {
    res.writeHead(404);
    res.end('not found: ' + e.message);
  }
});

server.listen(4310, '127.0.0.1', () => {
  console.log('poc static server on http://127.0.0.1:4310');
});
```

