### `source/repository.mjs`

This is the **GREEN / fixed** version. The RED bug (`eq(users.name, String(id))` in `getUser`) is documented inline as a comment but the shipped code uses the corrected `eq(users.id, id)` — this is the state that passes CI with exit code 0.

```js
import { eq } from 'drizzle-orm';
import { users } from './schema.mjs';

/**
 * Insert a row via .run(), then fetch it back using the driver-reported
 * lastInsertRowid (better-sqlite3's RunResult surfaces this on the
 * drizzle .run() return value — no need for a separate
 * `select last_insert_rowid()` raw query, though that pattern also works).
 */
export function createUser(db, { name, email }) {
  const result = db.insert(users).values({ name, email }).run();
  const id = Number(result.lastInsertRowid);
  return db.select().from(users).where(eq(users.id, id)).get();
}

/**
 * FIXED. RED angle for this POC was:
 *   return db.select().from(users).where(eq(users.name, String(id))).get();
 * — that compares the numeric id (cast to string) against the NAME column,
 * so it never matches and always returns `undefined`. The behavioral test
 * `getUser(db, 1)` after creating Alice (id=1) catches this because Alice's
 * name is "Alice", not "1".
 */
export function getUser(db, id) {
  return db.select().from(users).where(eq(users.id, id)).get();
}

export function listUsers(db) {
  return db.select().from(users).all();
}

export function updateUser(db, id, patch) {
  db.update(users).set(patch).where(eq(users.id, id)).run();
  return getUser(db, id);
}

export function deleteUser(db, id) {
  db.delete(users).where(eq(users.id, id)).run();
}
```

