### `source/repository.test.mjs`

```js
import { test } from 'node:test';
import assert from 'node:assert/strict';
import { eq } from 'drizzle-orm';

import { createDb } from './db.mjs';
import { users } from './schema.mjs';
import {
  createUser,
  getUser,
  listUsers,
  updateUser,
  deleteUser,
} from './repository.mjs';

test('createUser — returns inserted row with id, name, email', () => {
  const db = createDb();
  const alice = createUser(db, { name: 'Alice', email: 'alice@example.com' });
  console.log('CREATED:', JSON.stringify(alice));
  assert.equal(alice.id, 1);
  assert.equal(alice.name, 'Alice');
  assert.equal(alice.email, 'alice@example.com');
});

test('getUser — returns correct user by id (RED: wrong WHERE clause exposes bug)', () => {
  const db = createDb();
  createUser(db, { name: 'Alice', email: 'alice@example.com' });
  const got = getUser(db, 1);
  console.log('GOT USER:', JSON.stringify(got));
  assert.ok(got !== undefined);
  assert.equal(got.name, 'Alice');
});

test('listUsers — returns all inserted users', () => {
  const db = createDb();
  createUser(db, { name: 'Alice', email: 'alice@example.com' });
  createUser(db, { name: 'Bob', email: 'bob@example.com' });
  const all = listUsers(db);
  console.log('LIST:', JSON.stringify(all));
  assert.equal(all.length, 2);
});

test('updateUser — row reflects patched name after update', () => {
  const db = createDb();
  createUser(db, { name: 'Alice', email: 'alice@example.com' });
  createUser(db, { name: 'Bob', email: 'bob@example.com' });
  createUser(db, { name: 'Carol', email: 'carol@example.com' });
  const updated = updateUser(db, 3, { name: 'Carol Updated' });
  console.log('UPDATED:', JSON.stringify(updated));
  assert.equal(updated.id, 3);
  assert.equal(updated.name, 'Carol Updated');
});

test('deleteUser — row is gone after delete', () => {
  const db = createDb();
  createUser(db, { name: 'Alice', email: 'alice@example.com' });
  deleteUser(db, 1);
  const after = getUser(db, 1);
  console.log('AFTER DELETE (should be undefined):', after);
  assert.equal(after, undefined);
});

test('full lifecycle — create, get, list, update, delete; table shrinks by 1', () => {
  const db = createDb();
  createUser(db, { name: 'A', email: 'a@example.com' });
  createUser(db, { name: 'B', email: 'b@example.com' });
  createUser(db, { name: 'C', email: 'c@example.com' });
  createUser(db, { name: 'D', email: 'd@example.com' });

  const before = listUsers(db).length;
  deleteUser(db, 2);
  const after = listUsers(db).length;

  console.log('LIFECYCLE COMPLETE: before=', before, 'after=', after);
  assert.equal(before, 4);
  assert.equal(after, 3);
});

test('toSQL() — all four DML operations use ? placeholders, values only in params', () => {
  const db = createDb();

  const insertSql = db
    .insert(users)
    .values({ name: 'Zara', email: 'zara@example.com' })
    .toSQL();
  console.log('INSERT toSQL:', JSON.stringify(insertSql));

  const selectSql = db
    .select()
    .from(users)
    .where(eq(users.id, 42))
    .toSQL();
  console.log('SELECT toSQL:', JSON.stringify(selectSql));

  const updateSql = db
    .update(users)
    .set({ name: 'Zara2' })
    .where(eq(users.id, 42))
    .toSQL();
  console.log('UPDATE toSQL:', JSON.stringify(updateSql));

  const deleteSql = db.delete(users).where(eq(users.id, 42)).toSQL();
  console.log('DELETE toSQL:', JSON.stringify(deleteSql));

  for (const { sql, params } of [insertSql, selectSql, updateSql, deleteSql]) {
    assert.ok(sql.includes('?'), `expected placeholder in: ${sql}`);
    assert.ok(!sql.includes('Zara'), `value leaked into SQL string: ${sql}`);
    assert.ok(!sql.includes('42'), `value leaked into SQL string: ${sql}`);
    assert.ok(params.length > 0, 'expected non-empty params array');
  }
});
```

