```ts
import { defineTool } from "@flue/runtime";
import { z } from "zod";

export const getWeather = defineTool({
  name: "get_weather",
  description:
    "Get current temperature and coordinates/timezone for a place name. " +
    "Call this FIRST — its lat/lon/timezone feed get_air_quality and get_world_time.",
  input: z.object({
    location: z.string().describe("City name, e.g. 'Paris'"),
  }),
  run: async (ctx) => {
    const { location } = ctx.input;

    const geo = await fetch(
      `https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(
        location
      )}&count=1`
    ).then((r) => r.json());

    if (!geo.results?.length) {
      throw new Error(`No geocoding match for "${location}"`);
    }
    const { latitude, longitude, name, timezone } = geo.results[0];

    const wx = await fetch(
      `https://api.open-meteo.com/v1/forecast?latitude=${latitude}&longitude=${longitude}` +
        `&current=temperature_2m,weather_code&timezone=${encodeURIComponent(timezone)}`
    ).then((r) => r.json());

    return {
      location: name,
      latitude,
      longitude,
      timezone,
      temperatureC: wx.current.temperature_2m,
      weatherCode: wx.current.weather_code,
    };
  },
});
```

