## Step 2 — Extend: `get_air_quality` (Open-Meteo, keyless)

`source/capstone/tools/get-air-quality.ts`:

```ts
import { defineTool } from "@flue/runtime";
import { z } from "zod";

export const getAirQuality = defineTool({
  name: "get_air_quality",
  description:
    "Get current US AQI and PM2.5 for coordinates returned by get_weather.",
  input: z.object({
    latitude: z.number(),
    longitude: z.number(),
  }),
  run: async (ctx) => {
    const { latitude, longitude } = ctx.input;
    const res = await fetch(
      `https://air-quality-api.open-meteo.com/v1/air-quality` +
        `?latitude=${latitude}&longitude=${longitude}&current=us_aqi,pm2_5`
    );
    if (!res.ok) throw new Error(`Open-Meteo air-quality ${res.status}`);
    const data = await res.json();
    return {
      usAqi: data.current.us_aqi,
      pm2_5: data.current.pm2_5,
    };
  },
});
```

