import { defineTool } from "@flue/runtime";
import { z } from "zod";

export const getWorldTime = defineTool({
  name: "get_world_time",
  description:
    "Get current local time for an IANA timezone (e.g. from get_weather's timezone field).",
  input: z.object({
    timezone: z.string().describe("IANA tz, e.g. 'Europe/Paris'"),
  }),
  run: async (ctx) => {
    const { timezone } = ctx.input;
    // worldtimeapi.org was unreachable during build (connection reset) —
    // timeapi.io is the equivalent keyless replacement.
    const res = await fetch(
      `https://timeapi.io/api/time/current/zone?timeZone=${encodeURIComponent(
        timezone
      )}`
    );
    if (!res.ok) throw new Error(`timeapi.io ${res.status}`);
    const data = await res.json();
    return {
      timezone,
      dateTime: data.dateTime,
      time: `${String(data.hour).padStart(2, "0")}:${String(
        data.minute
      ).padStart(2, "0")}`,
    };
  },
});
```

