### `config-loader.mjs`

```js
import { z } from 'zod';

// ---------------------------------------------------------------------------
// AppConfigSchema
// ---------------------------------------------------------------------------
// port: z.coerce.number() — Number('8080') -> 8080 before min/max/int checks.
// .brand('Port') is a *type-level* nominal tag only. Zod's brand() method
// accepts a string argument purely so TS can narrow the literal type; at
// runtime it has zero effect on parsing — the wrapped schema (int/min/max)
// is what actually validates. Don't expect '.brand()' to add a runtime check.
//
// dbUrl / logLevel use the classic ZodString method-chain form (`.url()`).
// In zod 4, top-level `z.url()` / `z.email()` are the new preferred forms,
// but the legacy `.url()` method on `z.string()` still works identically in
// 4.4.3 — verified via safeParse below, no deprecation-driven runtime change.
export const AppConfigSchema = z.object({
  host: z.string().min(1),
  port: z.coerce.number().int().min(1).max(65535).brand('Port'),
  dbUrl: z.string().url(),
  logLevel: z.enum(['debug', 'info', 'warn', 'error']),
  maxRetries: z.coerce.number().int().min(0).max(10).optional().default(3),
});

export class ConfigError extends Error {
  constructor(message, issues) {
    super(message);
    this.name = 'ConfigError';
    // Raw ZodError.issues array attached verbatim — callers get full detail,
    // not just the formatted string.
    this.issues = issues;
  }
}

function formatIssues(issues) {
  return issues
    .map((issue) => `${issue.path.join('.') || '(root)'}: ${issue.message}`)
    .join('; ');
}

export function load(raw) {
  const result = AppConfigSchema.safeParse(raw);
  if (!result.success) {
    throw new ConfigError(
      `Invalid configuration: ${formatIssues(result.error.issues)}`,
      result.error.issues,
    );
  }
  return result.data;
}

// ---------------------------------------------------------------------------
// Generic request-body validator — HTTP-API-shaped result, no throwing.
// ---------------------------------------------------------------------------
export function validateRequestBody(schema, body) {
  const result = schema.safeParse(body);
  if (!result.success) {
    return {
      status: 422,
      errors: result.error.issues.map((issue) => ({
        path: issue.path.join('.'),
        message: issue.message,
      })),
    };
  }
  return { status: 200, data: result.data };
}
```

