import { test } from 'node:test';
import assert from 'node:assert/strict';
import { z } from 'zod';
import {
  AppConfigSchema,
  load,
  validateRequestBody,
  ConfigError,
} from './config-loader.mjs';

const validConfig = {
  host: 'api.example.com',
  port: '8080',                      // string -> coerced to number
  dbUrl: 'postgres://user:pass@localhost:5432/db',
  logLevel: 'info',
  maxRetries: '5',                   // string -> coerced to number
};

const validConfigNoRetries = {
  host: 'api.example.com',
  port: 8080,
  dbUrl: 'https://db.example.com',
  logLevel: 'debug',
  // maxRetries omitted -> defaults to 3
};

const invalidConfig = {
  host: '',                          // fails min(1)
  port: 'not-a-port',                // Number('not-a-port') = NaN -> fails int()
  dbUrl: 'not-a-url',                // fails url()
  logLevel: 'trace',                 // not in enum
  maxRetries: 999,                   // exceeds max(10)
};

test('L-capstone — typed config loader + request-body validator', async (t) => {
  await t.test('load(validConfig) returns typed object with coerced fields', () => {
    const config = load(validConfig);
    assert.equal(config.host, 'api.example.com');
    assert.equal(config.port, 8080);
    assert.equal(typeof config.port, 'number');
    assert.equal(config.maxRetries, 5);
  });

  await t.test('load(validConfig) defaults maxRetries to 3 when omitted', () => {
    const config = load(validConfigNoRetries);
    assert.equal(config.maxRetries, 3);
  });

  await t.test('load(invalidConfig) throws ConfigError', () => {
    assert.throws(() => load(invalidConfig), ConfigError);
  });

  await t.test('load(invalidConfig) ConfigError.issues is non-empty', () => {
    try {
      load(invalidConfig);
      assert.fail('expected load() to throw');
    } catch (err) {
      assert.ok(err instanceof ConfigError);
      assert.ok(Array.isArray(err.issues));
      assert.ok(err.issues.length > 0);
    }
  });

  await t.test('load(invalidConfig) formatted error message lists field paths', () => {
    try {
      load(invalidConfig);
      assert.fail('expected load() to throw');
    } catch (err) {
      assert.match(err.message, /host/);
      assert.match(err.message, /port/);
      assert.match(err.message, /dbUrl/);
      assert.match(err.message, /logLevel/);
    }
  });

  await t.test('validateRequestBody — valid body returns {status:200, data}', () => {
    const BodySchema = z.object({ name: z.string(), age: z.coerce.number().int() });
    const result = validateRequestBody(BodySchema, { name: 'Ada', age: '36' });
    assert.equal(result.status, 200);
    assert.deepEqual(result.data, { name: 'Ada', age: 36 });
  });

  await t.test('validateRequestBody — invalid body returns {status:422, errors}', () => {
    const BodySchema = z.object({ name: z.string(), age: z.coerce.number().int() });
    const result = validateRequestBody(BodySchema, { name: 42, age: 'not-a-number' });
    assert.equal(result.status, 422);
    assert.ok(Array.isArray(result.errors));
    assert.ok(result.errors.length > 0);
  });

  await t.test('validateRequestBody — errors array has correct path/message shape', () => {
    const BodySchema = z.object({ email: z.string().email() });
    const result = validateRequestBody(BodySchema, { email: 'not-an-email' });
    assert.equal(result.status, 422);
    assert.equal(result.errors[0].path, 'email');
    assert.equal(typeof result.errors[0].message, 'string');
  });

  await t.test('AppConfigSchema.safeParse(invalid) issues array — live evidence unit', () => {
    const result = AppConfigSchema.safeParse(invalidConfig);
    assert.equal(result.success, false);
    assert.ok(result.error.issues.length >= 4);
    const paths = result.error.issues.map((i) => i.path[0]);
    assert.ok(paths.includes('host'));
    assert.ok(paths.includes('dbUrl'));
    assert.ok(paths.includes('logLevel'));
  });
});
