### `agent/tools/get_weather.ts`

```ts
import { z } from "zod";
import { tool } from "eve";

export const getWeather = tool({
  name: "get_weather",
  description:
    "Get current weather conditions for a named city or location string.",
  parameters: z.object({
    location: z
      .string()
      .describe('City name or "City, Country", e.g. "Lisbon, Portugal"'),
  }),
  async execute({ location }) {
    // Real network call — no mock. Open-Meteo requires no API key, which
    // keeps this capstone runnable without an extra secret beyond
    // ANTHROPIC_API_KEY.
    const geo = await fetch(
      `https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(
        location
      )}&count=1`
    ).then((r) => r.json());

    const hit = geo?.results?.[0];
    if (!hit) {
      return { error: `No location found for "${location}"` };
    }

    const wx = await fetch(
      `https://api.open-meteo.com/v1/forecast?latitude=${hit.latitude}&longitude=${hit.longitude}&current=temperature_2m,wind_speed_10m`
    ).then((r) => r.json());

    return {
      location: `${hit.name}, ${hit.country}`,
      temperature_c: wx?.current?.temperature_2m,
      wind_speed_kmh: wx?.current?.wind_speed_10m,
    };
  },
});
```

**Inference flag**: `tool({...})` helper signature (named export from `"eve"`, `execute` async fn, plain-object return) mirrors the standard Vercel-AI-SDK-style tool shape referenced elsewhere in the corpus for zod-typed tools (consistent with zod 3.25.76 pinned in [3]). Confirm Eve's actual `tool()` export exists vs. a different name like `defineTool`.

