### `app/chat.tsx` — `useEveAgent` hook

```tsx
"use client";

import { useState } from "react";
import { useEveAgent } from "eve/react";

export default function Chat() {
  const [input, setInput] = useState("");

  // useEveAgent owns: session creation (POST /eve/v1/session), the NDJSON
  // stream connection (GET /eve/v1/session/:id/stream), and exposes
  // per-turn streaming state so the component can render token-by-token.
  const { messages, sendMessage, status } = useEveAgent({
    basePath: "/eve/v1",
  });

  const onSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;
    sendMessage(input);
    setInput("");
  };

  return (
    <div>
      <ul style={{ listStyle: "none", padding: 0 }}>
        {messages.map((m, i) => (
          <li key={i} style={{ margin: "8px 0" }}>
            <strong>{m.role === "user" ? "You" : "Eve"}:</strong> {m.content}
          </li>
        ))}
      </ul>

      {status === "streaming" && <p><em>Eve is typing…</em></p>}

      <form onSubmit={onSubmit}>
        <input
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Ask about the weather somewhere…"
          style={{ width: "80%" }}
        />
        <button type="submit" disabled={status === "streaming"}>
          Send
        </button>
      </form>
    </div>
  );
}
```

**Inference flag**: `useEveAgent({ basePath })` returning `{ messages, sendMessage, status }` is my inference of the minimal surface needed to satisfy "streaming turns and managing UI state" from your spec. The real hook may return richer state (e.g., per-message `toolCalls`, `error`); confirm against Eve's `.d.ts`.

