### `assert.mjs` — smoke test against the real deployment

```js
#!/usr/bin/env node
// Usage: node assert.mjs http://localhost:3018 <basic-auth-password>
//    or: node assert.mjs https://eve-poc-l8-capstone.vercel.app <basic-auth-password>

const [, , baseUrl, password] = process.argv;
if (!baseUrl || !password) {
  console.error("Usage: node assert.mjs <baseUrl> <basicAuthPassword>");
  process.exit(1);
}

const authHeader = "Basic " + Buffer.from(`smoke:${password}`).toString("base64");

async function main() {
  // 1. Health check — always public, no auth header.
  const health = await fetch(`${baseUrl}/eve/v1/health`);
  const healthBody = await health.json();
  assertEq(health.status, 200, "health status");
  assertEq(healthBody.ok, true, "health body.ok");
  console.log("PASS: GET /eve/v1/health ->", JSON.stringify(healthBody));

  // 2. Route-auth policy: session route must 401 WITHOUT auth (fail-closed).
  const unauth = await fetch(`${baseUrl}/eve/v1/session`, { method: "POST" });
  assertEq(unauth.status, 401, "unauthenticated session POST status");
  console.log("PASS: POST /eve/v1/session (no auth) -> 401 as expected");

  // 3. Create a session WITH Basic auth (smoke-test path).
  const sessionRes = await fetch(`${baseUrl}/eve/v1/session`, {
    method: "POST",
    headers: { Authorization: authHeader, "Content-Type": "application/json" },
    body: JSON.stringify({}),
  });
  assertEq(sessionRes.status, 200, "authenticated session POST status");
  const { sessionId } = await sessionRes.json();
  if (!sessionId) throw new Error("FAIL: no sessionId in session response");
  console.log("PASS: POST /eve/v1/session ->", sessionId);

  // 4. Send a turn that should trigger get_weather, then read the NDJSON stream.
  const turnRes = await fetch(`${baseUrl}/eve/v1/session/${sessionId}/turn`, {
    method: "POST",
    headers: { Authorization: authHeader, "Content-Type": "application/json" },
    body: JSON.stringify({ message: "What's the weather in Lisbon right now?" }),
  });
  assertEq(turnRes.status, 200, "turn POST status");

  const streamRes = await fetch(
    `${baseUrl}/eve/v1/session/${sessionId}/stream`,
    { headers: { Authorization: authHeader } }
  );
  assertEq(streamRes.status, 200, "stream GET status");

  const text = await streamRes.text();
  const lines = text.trim().split("\n").filter(Boolean);
  const events = lines.map((l) => JSON.parse(l));

  const sawToolCall = events.some(
    (e) => e.type === "tool_call" && e.name === "get_weather"
  );
  const sawAgentEnd = events.some((e) => e.type === "agent_end");

  if (!sawToolCall) throw new Error("FAIL: get_weather tool_call not observed in stream");
  if (!sawAgentEnd) throw new Error("FAIL: agent_end not observed in stream");

  console.log(`PASS: stream contains ${events.length} NDJSON events, tool_call=get_weather + agent_end confirmed`);
  console.log("\nSMOKE_OK_EVE_L8");
}

function assertEq(actual, expected, label) {
  if (actual !== expected) {
    throw new Error(`FAIL (${label}): expected ${expected}, got ${actual}`);
  }
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
```

**Inference flag**: The turn-submission endpoint (`POST /eve/v1/session/:id/turn`) and NDJSON event `type` values (`tool_call`, `agent_end`) are not in your route table (you only listed `health`, `session`, `session/:id/stream`) — I inferred a companion `turn` POST endpoint since a stream-only API needs *something* to push a user message in. This is the single largest unverified assumption in the whole implementation; if Eve instead multiplexes prompt-send over the SSE/NDJSON connection itself (e.g., a `POST` body directly to the stream URL, or a WS-style bidi channel), `assert.mjs` and `chat.tsx`'s `sendMessage` will need to match that instead. Given the corpus's precedent in [1] (`pi --mode rpc` uses a *separate* stdin JSON-command channel driving a *separate* stdout event stream — command-in / events-out, not unified), a split turn+stream design like mine is the more probable pattern, but flag it for verification against Eve's actual route table before relying on it.

