### `source/app/api/chat/route.ts` — real streaming `@anthropic-ai/sdk` call

Uses `messages.stream()` iterated as an async generator of raw `RawMessageStreamEvent`s (`message_start`, `content_block_delta`, etc.) — this is the documented low-level event interface, matching the key finding exactly. `ANTHROPIC_API_KEY` must be a real key; there is no fallback/mock path.

```typescript
import Anthropic from '@anthropic-ai/sdk';

export const runtime = 'nodejs';

const anthropic = new Anthropic({
  apiKey: process.env.ANTHROPIC_API_KEY,
});

export async function POST(request: Request) {
  const { prompt } = await request.json();
  const encoder = new TextEncoder();

  const readable = new ReadableStream({
    async start(controller) {
      try {
        const anthropicStream = anthropic.messages.stream({
          model: 'claude-haiku-4-5',
          max_tokens: 1024,
          messages: [{ role: 'user', content: prompt }],
        });

        for await (const event of anthropicStream) {
          if (event.type === 'message_start') {
            const { id, model } = event.message;
            controller.enqueue(encoder.encode(`META ${id} ${model}\n`));
          } else if (
            event.type === 'content_block_delta' &&
            event.delta.type === 'text_delta'
          ) {
            controller.enqueue(encoder.encode(event.delta.text));
          }
        }

        controller.close();
      } catch (err) {
        controller.error(err);
      }
    },
  });

  return new Response(readable, {
    headers: {
      'Content-Type': 'text/plain; charset=utf-8',
      'Cache-Control': 'no-cache',
      'X-Content-Type-Options': 'nosniff',
    },
  });
}
```

