```typescript
import "dotenv/config";
import { createAgent, defineTool, defineWorkflow } from "@flue/runtime";
import { local } from "@flue/runtime/node";
import * as v from "valibot";
import { readFile } from "node:fs/promises";
import { join } from "node:path";

// Module-level flag flipped only by the tool's handler. This is the only
// reliable way to assert "the tool actually ran" independent of what the
// model claims in its final text — the whole point of the capstone test.
let toolWasCalled = false;

const readFileTool = defineTool({
  name: "read_file",
  description:
    "Reads the full text contents of a file located in the workspace " +
    "directory, given its filename. You MUST call this before summarizing " +
    "— you have no other way to know what the file contains.",
  input: v.object({
    filename: v.string(),
  }),
  handler: async ({ filename }: { filename: string }) => {
    toolWasCalled = true;
    const path = join(process.cwd(), "workspace", filename);
    return await readFile(path, "utf-8");
  },
});

// Local Node.js sandbox. The tool above does the fs read directly (no shell
// exec), so this sandbox is wired in to demonstrate the sandbox API surface
// per the capstone's stated goals, not because read_file needs it.
const sandbox = local({
  cwd: process.cwd(),
});

const summarizerAgent = createAgent({
  model: "anthropic:claude-haiku-4-5",
  instructions:
    "You are a file-summarization agent. When asked to summarize a file, " +
    "you MUST call the read_file tool with the exact filename given, " +
    "FIRST, before writing anything. Never guess or hallucinate file " +
    "content. After the tool returns content, respond with EXACTLY ONE " +
    "sentence that grounds the summary in that content.",
  tools: [readFileTool],
  sandbox,
});

export const readAndSummarize = defineWorkflow({
  name: "read-and-summarize",
  input: v.object({ filename: v.string() }),
  handler: async ({ filename }: { filename: string }) => {
    toolWasCalled = false;

    const result = await summarizerAgent.invoke({
      messages: [
        {
          role: "user",
          content: `Read the file "${filename}" and give me a one-sentence summary of its contents.`,
        },
      ],
    });

    const finalMessage = result.messages[result.messages.length - 1];
    const summary =
      typeof finalMessage.content === "string"
        ? finalMessage.content
        : JSON.stringify(finalMessage.content);

    return {
      summary,
      toolCalled: toolWasCalled,
    };
  },
});

export default readAndSummarize;
```

