```javascript
#!/usr/bin/env node
import { execFile } from "node:child_process";
import { promisify } from "node:util";

const execFileAsync = promisify(execFile);
const mode = process.argv[2] ?? "green";

async function runWorkflow(payload) {
  const { stdout, stderr } = await execFileAsync(
    "npx",
    [
      "flue",
      "run",
      "read-and-summarize",
      "--target",
      "node",
      "--payload",
      JSON.stringify(payload),
    ],
    { cwd: process.cwd(), env: process.env, maxBuffer: 1024 * 1024 }
  );

  if (stderr) console.error("[stderr]", stderr);
  console.log("[raw stdout]", stdout);

  // `flue run` is expected to print a JSON result somewhere in stdout.
  // Extract the last JSON-looking line rather than assuming the whole
  // stdout is pure JSON (CLI banners/log lines may precede it).
  const jsonLine = stdout
    .trim()
    .split("\n")
    .reverse()
    .find((line) => line.trim().startsWith("{"));

  if (!jsonLine) {
    throw new Error("Could not find JSON result in `flue run` stdout");
  }

  return JSON.parse(jsonLine);
}

async function main() {
  const payload = { filename: "input.txt" };
  const result = await runWorkflow(payload);

  console.log("--- parsed result ---");
  console.log(JSON.stringify(result, null, 2));

  const assertions = [];

  if (mode === "red") {
    // RED proves the harness can actually fail: assert the summary equals a
    // string the model would never produce if read_file genuinely ran and
    // fed real content. Against the real, correct workflow this MUST fail.
    assertions.push([
      "summary equals deliberately-wrong hardcoded string (must FAIL against real workflow)",
      result.summary.trim() === "The file is about bananas.",
    ]);
  } else {
    assertions.push(["toolCalled === true", result.toolCalled === true]);
    assertions.push([
      "summary is non-empty string",
      typeof result.summary === "string" && result.summary.length > 0,
    ]);
    assertions.push([
      "summary grounded in Eiffel Tower content",
      /eiffel|tower|paris|1889/i.test(result.summary),
    ]);
  }

  let allPass = true;
  for (const [label, pass] of assertions) {
    console.log(`${pass ? "PASS" : "FAIL"} — ${label}`);
    if (!pass) allPass = false;
  }

  process.exit(allPass ? 0 : 1);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
```

