```js
// Thin wrapper for driving a headless Pi coding-agent turn *inside* an
// AgentOs VM, using Pi's own live-verified print-mode contract:
// `pi -p "<prompt>"` -> exit 0, sentinel string present in stdout
// (Live Evidence Ledger, POC L0: `SMOKE_OK_PI_L0` in ~615ms wall-clock;
// POC L1-B-L1-1/2 for session + RPC-mode confirmation).
//
// ASSUMPTION FLAG: `vm.exec()` is inferred as the AgentOs VM's
// process-exec surface. The task's own Intent section only names
// `vm.readFile` / `vm.writeFile` / `vm.dispose` explicitly; `vm.exec` is
// inferred from "software: [pi]" (pi installed as an executable inside
// the VM). If your AgentOs build names this differently (`vm.spawn`,
// `vm.run`, etc.), only this file needs to change.

export async function execInVm(vm, command, { timeoutMs = 60_000 } = {}) {
  const result = await vm.exec(command, {
    stdin: "",        // closed stdin — per pi quickstart guidance (note [1])
    timeoutMs,
  });
  if (result.exitCode !== 0) {
    throw new Error(
      `execInVm failed (exit ${result.exitCode}) for: ${command}\n` +
      `stdout: ${result.stdout}\nstderr: ${result.stderr}`
    );
  }
  return result.stdout;
}

export function buildPiPrintCommand({
  promptFile,
  model = "claude-haiku-4-5",   // live-verified Anthropic model id, note [3]
  cwd = "/workspace",
}) {
  return (
    `cd ${cwd} && pi -p "$(cat ${promptFile})" ` +
    `--provider anthropic --model ${model} --mode text`
  );
}
```

