### `src/probe-capstone2.mjs` (the GREEN-state sequential probe)

```js
#!/usr/bin/env node
// L-capstone-agent-to-agent-review — GREEN STATE
//
// Two isolated Pi agent sessions, each in its own AgentOs VM, collaborate
// through HOST-SIDE artifact bridging (vm.readFile / vm.writeFile). The
// coder and reviewer actions are driven as SEQUENTIAL, TOP-LEVEL HOST
// CALLS — never nested inside a binding `execute` — to avoid exhausting
// the per-action wasm_fuel_ms CPU budget (30,000 ms). See
// src/red-state/nested-binding-repro.mjs for the failure this avoids.
//
// Requires: ANTHROPIC_API_KEY (two live Claude round-trips: coder + reviewer)
// Run: node src/probe-capstone2.mjs

import { readFile, writeFile, mkdir } from "node:fs/promises";
import { fileURLToPath } from "node:url";
import path from "node:path";
import { AgentOs } from "@agentos/sdk";
import { pi } from "@earendil-works/pi-coding-agent/software"; // ASSUMED export surface for "software: [pi]"
import { execInVm, buildPiPrintCommand } from "./lib/run-pi-in-vm.mjs";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const CODER_PROMPT_PATH = path.join(__dirname, "prompts/coder-prompt.txt");
const REVIEWER_PROMPT_PATH = path.join(__dirname, "prompts/reviewer-prompt.txt");
const LOG_DIR = path.join(__dirname, "../logs");

function requireEnv(name) {
  const v = process.env[name];
  if (!v) throw new Error(`Missing required env var: ${name}`);
  return v;
}

async function main() {
  const t0 = Date.now();
  const ANTHROPIC_API_KEY = requireEnv("ANTHROPIC_API_KEY");
  await mkdir(LOG_DIR, { recursive: true });

  // ---- STEP 1-2: boot coder VM, drive coder action to COMPLETION ----
  const coder = await AgentOs.create({
    software: [pi],
    env: { ANTHROPIC_API_KEY },
  });

  let coderStdout;
  try {
    const coderPrompt = await readFile(CODER_PROMPT_PATH, "utf8");
    await coder.writeFile("/workspace/coder-prompt.txt", coderPrompt);

    coderStdout = await execInVm(
      coder,
      buildPiPrintCommand({ promptFile: "/workspace/coder-prompt.txt" })
    );

    if (!coderStdout.includes("SMOKE_OK_CODER_WROTE_FILE")) {
      throw new Error(`Coder sentinel not found. stdout:\n${coderStdout}`);
    }
  } catch (err) {
    await coder.dispose().catch(() => {});
    throw err;
  }

  // ---- STEP 3: host reads the artifact OUT of the coder VM ----
  const mathJsSource = await coder.readFile("/workspace/math.js");
  if (!mathJsSource.includes("a - b")) {
    await coder.dispose().catch(() => {});
    throw new Error(`Coder did not write the expected buggy impl:\n${mathJsSource}`);
  }

  // Coder's job is fully done — dispose it BEFORE starting the
  // reviewer's live LLM call. This is the sequential-not-nested fix.
  await coder.dispose();

  // ---- STEP 4: boot a SEPARATE, independent reviewer VM ----
  const reviewer = await AgentOs.create({
    software: [pi],
    env: { ANTHROPIC_API_KEY },
  });

  let reviewerStdout;
  try {
    // ---- STEP 5: host writes the artifact INTO the reviewer VM ----
    await reviewer.writeFile("/workspace/math.js", mathJsSource);

    const reviewerPrompt = await readFile(REVIEWER_PROMPT_PATH, "utf8");
    await reviewer.writeFile("/workspace/reviewer-prompt.txt", reviewerPrompt);

    // ---- STEP 6: drive the reviewer action to COMPLETION ----
    reviewerStdout = await execInVm(
      reviewer,
      buildPiPrintCommand({ promptFile: "/workspace/reviewer-prompt.txt" })
    );
  } finally {
    // ---- STEP 8: dispose reviewer (coder already disposed above) ----
    await reviewer.dispose().catch(() => {});
  }

  // ---- STEP 7: assert the reviewer caught the bug ----
  const verdictMatch = reviewerStdout.match(/VERDICT:\s*(BUG_FOUND|NO_BUG_FOUND)/);
  const verdict = verdictMatch ? verdictMatch[1] : null;
  const totalMs = Date.now() - t0;

  await writeFile(
    path.join(LOG_DIR, "green-output.txt"),
    `coder stdout:\n${coderStdout}\n\n` +
    `math.js as read by host:\n${mathJsSource}\n\n` +
    `reviewer stdout:\n${reviewerStdout}\n\n` +
    `verdict: ${verdict}\ntotal_ms: ${totalMs}\n`
  );

  if (verdict !== "BUG_FOUND") {
    console.error(`=> CAPSTONE-SEQ FAIL (reviewer verdict: ${verdict}) total ${totalMs} ms`);
    process.exit(1);
  }

  console.log(`=> CAPSTONE-SEQ PASS (reviewer caught the bug) total ${totalMs} ms`);
  process.exit(0);
}

main().catch((err) => {
  console.error("=> CAPSTONE-SEQ FAIL (unhandled error)");
  console.error(err);
  process.exit(1);
});
```

