### `src/red-state/nested-binding-repro.mjs` (documents the RED state — regression fixture, not the passing path)

```js
// RED-STATE REPRODUCTION — kept as a regression fixture, NOT wired into
// the passing CI path. Documents exactly why probe-capstone2.mjs drives
// coder and reviewer as sequential top-level host calls instead of
// nesting the reviewer's full agent turn inside a binding `execute`.
//
// Failure mechanism: the coder agent calls a custom CLI-shaped binding,
//   agentos-review submit --path /workspace/math.js
// whose `execute` runs ON THE HOST but is invoked synchronously from
// inside the coder's still-in-flight tool-call action. Booting a second
// full Pi agent session (the reviewer) and awaiting its live Claude
// round-trip from inside that execute exhausts the coder action's
// wasm_fuel_ms budget (30,000 ms) before the reviewer's LLM call can
// return.
//
// Observed (live-verified in the corpus's capstone POC):
//   sidecar log: "bounded limit exhausted"
//   thrown:      Error: timed out waiting for sidecar protocol frame for ext

import { AgentOs } from "@agentos/sdk";
import { pi } from "@earendil-works/pi-coding-agent/software";

const AGENTOS_REVIEW_BINDING = {
  name: "agentos-review",
  // Invoked by the coder agent as:
  //   agentos-review submit --path /workspace/math.js
  async execute({ args }) {
    const filePath = args["--path"];

    // ANTI-PATTERN: booting + prompting a second full agent session
    // SYNCHRONOUSLY inside this execute, while the coder's own action
    // clock (wasm_fuel_ms) is already running.
    const reviewer = await AgentOs.create({ software: [pi] });
    await reviewer.writeFile(filePath, "/* artifact injected mid-flight */");
    const stdout = await reviewer.exec(
      `pi -p "Review ${filePath}" --provider anthropic --model claude-haiku-4-5`
    );
    await reviewer.dispose();
    return stdout; // usually never reached — times out first
  },
};

export async function reproduceRedState() {
  const coder = await AgentOs.create({
    software: [pi],
    bindings: [AGENTOS_REVIEW_BINDING],
  });
  try {
    // Nests the reviewer's ENTIRE agent turn inside the coder's own
    // tool-call execution window — this is the re-entrant pattern that
    // blows the 30,000 ms wasm_fuel_ms budget.
    await coder.exec(
      `pi -p "Write /workspace/math.js, then call agentos-review submit --path /workspace/math.js" ` +
      `--provider anthropic --model claude-haiku-4-5`
    );
  } finally {
    await coder.dispose().catch(() => {});
  }
}
```

