```javascript
export function msUntilReset(resetHeaderValue, now = Date.now()) {
  const resetEpochSeconds = Number(resetHeaderValue)
  if (!Number.isFinite(resetEpochSeconds)) return 0
  const resetMs = resetEpochSeconds * 1000
  const delta = resetMs - now
  return delta > 0 ? delta : 0
}

/**
 * P5: proactive, reset-aware backoff — no tight-retry loop.
 * Reads x-rate-limit-reset and waits exactly that long (once), never spins.
 */
export async function backoffOn429(response, sleepFn = (ms) => new Promise((r) => setTimeout(r, ms))) {
  if (response.status !== 429) return 0
  const reset = response.headers.get('x-rate-limit-reset')
  const wait = msUntilReset(reset)
  if (wait > 0) await sleepFn(wait)
  return wait
}
