// FLAGSHIP finding (live-verified, earlier levels): X API v2 error envelope is
// problem+json { title, type, status, detail } — NOT the v1.1 { errors: [{ code, message }] } shape.
export function isProblemJson(body) {
  return !!body && typeof body === 'object' &&
    typeof body.title === 'string' &&
    typeof body.status === 'number' &&
    'type' in body
}

export class XApiError extends Error {
  constructor(problem, status) {
    super(problem?.detail || problem?.title || `X API error ${status}`)
    this.name = 'XApiError'
    this.status = status
    this.problem = problem
  }
}

export function classifyError(status /*, problem */) {
  if (status === 401) return 'AUTH_INVALID_OR_EXPIRED'
  if (status === 403) return 'FORBIDDEN_WRONG_AUTH_MODE_OR_SCOPE' // e.g. App-Only Bearer used for a write
  if (status === 429) return 'RATE_LIMITED'
  if (status >= 500) return 'X_SERVER_ERROR'
  return 'UNKNOWN'
}
