// P11/P12: never persist raw X content or secrets beyond the run; redact before logging.
const SENSITIVE_KEYS = new Set([
  'authorization', 'access_token', 'refresh_token', 'code', 'code_verifier', 'client_secret',
])

export function redact(obj) {
  if (Array.isArray(obj)) return obj.map(redact)
  if (obj && typeof obj === 'object') {
    const out = {}
    for (const [k, v] of Object.entries(obj)) {
      out[k] = SENSITIVE_KEYS.has(k.toLowerCase()) ? '[REDACTED]' : redact(v)
    }
    return out
  }
  return obj
}

export function logEvent(event, data = {}) {
  const line = JSON.stringify({ ts: new Date().toISOString(), event, ...redact(data) })
  console.log(line)
  return line
}
