## `source/lib/write-client.mjs`

```javascript
import { backoffOn429 } from './backoff.mjs'
import { isProblemJson, XApiError } from './error-handler.mjs'
import { logEvent } from './observability.mjs'

const API_BASE = 'https://api.twitter.com/2'

// Documented per-call cost table (P15) — used to enforce a hard spend cap client-side,
// independent of whatever billing X applies server-side.
export const COST_TABLE = {
  create: 0.015,   // link-free post; $0.20 if it contained a URL
  read: 0.005,     // verify GET
  ownedRead: 0.001,
  delete: 0.0,
}

export class SpendCapExceededError extends Error {
  constructor(capUsd, wouldBeUsd) {
    super(`Spend cap $${capUsd} would be exceeded by this run ($${wouldBeUsd.toFixed(3)})`)
    this.name = 'SpendCapExceededError'
  }
}

export function estimateRunCostUsd() {
  return COST_TABLE.create + COST_TABLE.read + COST_TABLE.ownedRead + COST_TABLE.delete
}

export function assertUnderSpendCap(capUsd) {
  const estimated = estimateRunCostUsd()
  if (estimated > capUsd) throw new SpendCapExceededError(capUsd, estimated)
  return estimated
}

async function requestWithBackoff(url, opts, { maxRetries = 1 } = {}) {
  let attempt = 0
  while (true) {
    const res = await fetch(url, opts)
    logEvent('rate_limit_snapshot', {
      url,
      status: res.status,
      remaining: res.headers.get('x-rate-limit-remaining'),
      limit: res.headers.get('x-rate-limit-limit'),
      reset: res.headers.get('x-rate-limit-reset'),
    })
    if (res.status === 429 && attempt < maxRetries) {
      attempt += 1
      const waited = await backoffOn429(res)
      logEvent('backoff_429', { url, waitedMs: waited })
      continue
    }
    return res
  }
}

async function parseJsonSafe(res) {
  const text = await res.text()
  try { return JSON.parse(text) } catch { return { raw: text } }
}

function throwIfError(res, body) {
  if (res.ok) return
  if (isProblemJson(body)) throw new XApiError(body, res.status)
  throw new XApiError({ title: 'unknown_error', type: 'about:blank', status: res.status, detail: JSON.stringify(body) }, res.status)
}

export function makeXClient({ accessToken, spendCapUsd }) {
  assertUnderSpendCap(spendCapUsd)

  async function createPost(text) {
    if (/https?:\/\//i.test(text)) {
      throw new Error('P15 violation: post text contains a URL ($0.20 tier) — aborting, expected link-free ($0.015)')
    }
    const res = await requestWithBackoff(`${API_BASE}/tweets`, {
      method: 'POST',
      headers: { Authorization: `Bearer ${accessToken}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ text }),
    })
    const body = await parseJsonSafe(res)
    throwIfError(res, body)
    return body.data // { id, text }
  }

  async function verifyPost(id) {
    const res = await requestWithBackoff(`${API_BASE}/tweets/${id}`, {
      headers: { Authorization: `Bearer ${accessToken}` },
    })
    const body = await parseJsonSafe(res)
    throwIfError(res, body)
    return body.data
  }

  async function deletePost(id) {
    const res = await requestWithBackoff(`${API_BASE}/tweets/${id}`, {
      method: 'DELETE',
      headers: { Authorization: `Bearer ${accessToken}` },
    })
    const body = await parseJsonSafe(res)
    throwIfError(res, body)
    // P2: mandatory-delete guard — never treat the run as safe unless the API confirms it.
    if (body.data?.deleted !== true) {
      throw new Error('MANDATORY-DELETE GUARD TRIPPED: delete response did not confirm deleted:true')
    }
    return body.data
  }

  return { createPost, verifyPost, deletePost }
}

/**
 * The single composed capstone action: create -> verify -> delete (max 3 calls, P6).
 * Throws — does not silently continue — if the delete isn't confirmed.
 */
export async function safePostRoundTrip({ accessToken, text, spendCapUsd }) {
  const client = makeXClient({ accessToken, spendCapUsd })
  logEvent('round_trip_start', { textLength: text.length })

  const created = await client.createPost(text)
  logEvent('post_created', { id: created.id })

  const verified = await client.verifyPost(created.id)
  logEvent('post_verified', { id: verified.id, matchesText: verified.text === text })

  const deleted = await client.deletePost(created.id)
  logEvent('post_deleted', { id: created.id, deleted: deleted.deleted })

  return { id: created.id, text: created.text, deleted: deleted.deleted }
}
