## `source/app.mjs`

```javascript
import { Hono } from 'hono'
import { randomUUID } from 'node:crypto'
import { generateCodeVerifier, generateCodeChallengeS256, generateState } from './lib/pkce.mjs'
import { safePostRoundTrip, assertUnderSpendCap, SpendCapExceededError } from './lib/write-client.mjs'
import { isProblemJson, classifyError } from './lib/error-handler.mjs'
import { logEvent } from './lib/observability.mjs'

const app = new Hono()

const AUTH_BASE = 'https://twitter.com/i/oauth2/authorize'
const TOKEN_URL = 'https://api.twitter.com/2/oauth2/token'
const SCOPES = 'tweet.write tweet.read users.read' // P14: narrowest scopes, no offline.access unless refresh needed

// In-memory PKCE store, this process only — cleared on exit (P12: store only what's needed).
const pkceStore = new Map()

app.get('/health', (c) => c.json({ ok: true }))

app.get('/auth/start', (c) => {
  const clientId = process.env.X_CLIENT_ID
  const redirectUri = process.env.X_REDIRECT_URI || 'http://127.0.0.1:8787/auth/callback'
  if (!clientId) {
    return c.json({ title: 'missing_client_id', type: 'about:blank', status: 500, detail: 'X_CLIENT_ID not set' }, 500)
  }

  const verifier = generateCodeVerifier()
  const challenge = generateCodeChallengeS256(verifier)
  const state = generateState()
  pkceStore.set(state, { verifier, createdAt: Date.now() })

  const url = new URL(AUTH_BASE)
  url.searchParams.set('response_type', 'code')
  url.searchParams.set('client_id', clientId)
  url.searchParams.set('redirect_uri', redirectUri)
  url.searchParams.set('scope', SCOPES)
  url.searchParams.set('state', state)
  url.searchParams.set('code_challenge', challenge)
  url.searchParams.set('code_challenge_method', 'S256')

  return c.redirect(url.toString())
})

app.get('/auth/callback', async (c) => {
  const code = c.req.query('code')
  const state = c.req.query('state')
  const clientId = process.env.X_CLIENT_ID
  const clientSecret = process.env.X_CLIENT_SECRET
  const redirectUri = process.env.X_REDIRECT_URI || 'http://127.0.0.1:8787/auth/callback'

  const stored = pkceStore.get(state)
  if (!code || !state || !stored) {
    return c.json({ title: 'invalid_state_or_code', type: 'about:blank', status: 400 }, 400)
  }
  pkceStore.delete(state) // one-time use

  const basicAuth = Buffer.from(`${clientId}:${clientSecret}`).toString('base64')
  const res = await fetch(TOKEN_URL, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
      Authorization: `Basic ${basicAuth}`,
    },
    body: new URLSearchParams({
      grant_type: 'authorization_code',
      code,
      redirect_uri: redirectUri,
      code_verifier: stored.verifier,
    }),
  })
  const body = await res.json()
  logEvent('token_exchange', { status: res.status, ok: res.ok })

  if (!res.ok) {
    return c.json(
      isProblemJson(body) ? body : { title: 'token_exchange_failed', type: 'about:blank', status: res.status, detail: JSON.stringify(body) },
      res.status,
    )
  }

  // access_token is NOT persisted to disk — held only for the duration of the run (P12).
  return c.json({ ok: true, expires_in: body.expires_in, scope: body.scope, note: 'access_token held in-memory only; not persisted' })
})

/**
 * The capstone action. Requires a user-context access token (obtained via /auth/callback in a
 * real run) plus a spend cap. Executes create -> verify -> delete exactly once (P6, P7).
 */
app.post('/run', async (c) => {
  const accessToken = c.req.header('x-access-token') || process.env.X_USER_ACCESS_TOKEN
  const spendCapUsd = Number(process.env.X_SPEND_CAP_USD || '0.02')

  if (!accessToken) {
    return c.json({ title: 'missing_access_token', type: 'about:blank', status: 401, detail: 'No user access token available' }, 401)
  }

  try {
    assertUnderSpendCap(spendCapUsd)
  } catch (err) {
    if (err instanceof SpendCapExceededError) {
      return c.json({ title: 'spend_cap_exceeded', type: 'about:blank', status: 402, detail: err.message }, 402)
    }
    throw err
  }

  const testId = randomUUID()
  const text = `Automated test post — agent-university capstone verification ${testId} (will be deleted immediately)`

  try {
    const result = await safePostRoundTrip({ accessToken, text, spendCapUsd })
    return c.json({ ok: true, result })
  } catch (err) {
    logEvent('round_trip_error', {
      message: err.message,
      status: err.status,
      classification: err.status ? classifyError(err.status) : undefined,
    })
    const status = err.status || 500
    return c.json(err.problem ?? { title: 'round_trip_failed', type: 'about:blank', status, detail: err.message }, status)
  }
})

export default app
```

