      throw new Error('MANDATORY-DELETE GUARD TRIPPED: deleted !== true')
    }
    return deleteResponseData
  }
  assert.throws(() => assertDeleted({ deleted: false }), /MANDATORY-DELETE GUARD/)
  assert.throws(() => assertDeleted({}), /MANDATORY-DELETE GUARD/)
  assert.doesNotThrow(() => assertDeleted({ deleted: true, id: '123' }))
})

test('msUntilReset: computes correct wait window from unix epoch seconds', () => {
  const now = 1_700_000_000_000
  const futureReset = String(Math.floor(now / 1000) + 30)
  const pastReset = String(Math.floor(now / 1000) - 30)
  assert.equal(msUntilReset(futureReset, now), 30_000)
  assert.equal(msUntilReset(pastReset, now), 0)
