// Vite plugin: server-side /api/chat proxy → Anthropic stream → OpenAI-style SSE
import type { Plugin, Connect } from "vite";
import Anthropic from "@anthropic-ai/sdk";
import { openuiLibrary } from "../lib/openui-library";       // custom library, from L1
import { openuiPromptOptions } from "../lib/prompt-options"; // options passed to .prompt()

const MODEL = "claude-sonnet-4-6";
const MAX_TOKENS = 1600;

// Cache the system prompt across requests — avoids re-walking the component
// registry (Stack, BarChart, Card, Table, ...) on every turn.
let promptCache: string | null = null;

function getSystemPrompt(): string {
  if (promptCache === null) {
    promptCache = openuiLibrary.prompt(openuiPromptOptions); // SSR module load
  }
  return promptCache;
}

interface IncomingChatMessage {
  role: "user" | "assistant" | "system";
  content: string;
}

function readBody(req: Connect.IncomingMessage): Promise<string> {
  return new Promise((resolve, reject) => {
    let data = "";
    req.on("data", (chunk) => (data += chunk));
    req.on("end", () => resolve(data));
    req.on("error", reject);
  });
}

export function chatPlugin(): Plugin {
  return {
