        const apiKey = process.env.ANTHROPIC_API_KEY;
        if (!apiKey) {
          res.statusCode = 500;
          res.end(JSON.stringify({ error: "ANTHROPIC_API_KEY not set on server" }));
          return;
        }

        const raw = await readBody(req);
        let payload: { messages: IncomingChatMessage[] };
        try {
          payload = JSON.parse(raw);
        } catch {
          res.statusCode = 400;
          res.end(JSON.stringify({ error: "invalid JSON body" }));
          return;
        }

        const anthropic = new Anthropic({ apiKey });

        const anthropicMessages = payload.messages
          .filter((m) => m.role !== "system")
          .map((m) => ({
            role: m.role === "assistant" ? ("assistant" as const) : ("user" as const),
            content: m.content,
          }));

        res.writeHead(200, {
          "Content-Type": "text/event-stream",
          "Cache-Control": "no-cache",
          Connection: "keep-alive",
        });

        const stream = anthropic.messages.stream({
          model: MODEL,
          max_tokens: MAX_TOKENS,
          system: getSystemPrompt(),
          messages: anthropicMessages,
        });

        // Re-emit Anthropic text deltas as OpenAI-style SSE chunks so
        // openAIAdapter() on the client can parse them unmodified.
        stream.on("text", (delta) => {
          res.write(
            `data: ${JSON.stringify({ choices: [{ delta: { content: delta } }] })}\n\n`
          );
        });

        stream.on("end", () => {
          res.write("data: [DONE]\n\n");
          res.end();
        });

        stream.on("error", (err) => {
          res.write(
            `data: ${JSON.stringify({
              choices: [{ delta: { content: `\n[error: ${String(err)}]` } }],
            })}\n\n`
          );
          res.write("data: [DONE]\n\n");
          res.end();
        });
      });
    },
  };
}
