import { useState } from "react";
import {
  ChatProvider,
  useThread,
  fetchLLM,
  openAIAdapter,
  openAIMessageFormat,
} from "@openuidev/react-headless"; // NOT "@openuidev/react" — that name doesn't exist on npm
import { Renderer } from "@openuidev/react";
import { openuiLibrary } from "../lib/openui-library";

function Bubble({
  role,
  content,
  isStreaming,
}: {
  role: string;
  content: string;
  isStreaming: boolean;
}) {
  return (
    <div data-role={role} className={`bubble bubble-${role}`}>
      {role === "assistant" ? (
        <Renderer library={openuiLibrary} response={content} isStreaming={isStreaming} />
      ) : (
        <span>{content}</span>
      )}
    </div>
  );
}

function ChatWindow() {
  const { messages, isRunning, processMessage } = useThread();
  const [input, setInput] = useState("");

  const onSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isRunning) return;
    processMessage({
      content: input,
      run: fetchLLM({
        url: "/api/chat",
        adapter: openAIAdapter(),
        format: openAIMessageFormat,
      }),
    });
    setInput("");
  };

  return (
    <div id="l9-chat-root">
      <div id="messages">
        {messages.map((m, i) => (
          <Bubble
            key={i}
            role={m.role}
            content={m.content}
            isStreaming={isRunning && i === messages.length - 1 && m.role === "assistant"}
          />
        ))}
      </div>
      <form onSubmit={onSubmit}>
        <input
          data-testid="l9-input"
          value={input}
          onChange={(e) => setInput(e.target.value)}
        />
        <button data-testid="l9-send" type="submit" disabled={isRunning}>
          Send
        </button>
      </form>
      {/* Playwright waits on this: "1" while the Anthropic stream is open,
          "0" once fetchLLM/useThread report it settled. */}
      <div data-testid="l9-sentinel" data-running={isRunning ? "1" : "0"} />
    </div>
  );
}

export function L9Harness() {
  return (
    <ChatProvider>
      <ChatWindow />
    </ChatProvider>
  );
}
