Below is a stdlib‑only implementation matching the required architecture. **Honesty flag up front**: none of the 6 corpus notes you gave me are OpenRouter‑specific (they're LangGraph/CrewAI/pi/LangSmith/Nango) — the only genuinely transferable pattern is gotcha [6]'s principle ("the agent only holds one secret for the broker; it never injects a second auth layer for the downstream provider"), which maps directly onto OpenRouter (you only ever send `Authorization: Bearer $OPENROUTER_API_KEY` to `openrouter.ai`; you never add separate keys for `perplexity/sonar` or `openai/gpt-4o-mini` — OpenRouter is the sole auth boundary). Everything else below is written directly against OpenRouter's public REST contract, not verified against a live_verified POC in this corpus, so I flag the two riskiest assumptions inline (marked ⚠️) rather than pretending they're pre-confirmed.

## `source/poc_capstone.py`

```python
"""
L-Capstone: Cost-Aware, Schema-Guaranteed, Fault-Tolerant Research Answerer

Stdlib-only (urllib). Requires OPENROUTER_API_KEY in the environment.

Architecture:
    Question -> [perplexity/sonar]            -> raw_answer + citations[]
             -> [openai/gpt-4o-mini + json_schema] -> {answer, citations}
             -> [GET /generation?id=... x2]    -> total_cost
"""
import json
import os
import time
import urllib.error
import urllib.request
from functools import lru_cache

OPENROUTER_BASE = "https://openrouter.ai/api/v1"
API_KEY = os.environ.get("OPENROUTER_API_KEY")

RESEARCH_MODEL = "perplexity/sonar"
SCHEMA_MODEL = "openai/gpt-4o-mini"

# ⚠️ Assumption (not corpus-verified here): a syntactically valid but
# nonexistent "vendor/model" string is enough to force OpenRouter's
# `models` fallback chain to skip to the next entry. If OpenRouter instead
# hard-validates model IDs and 400s before ever attempting fallback, swap
# this for a real-but-usually-saturated model id and re-verify live.
FAKE_PRIMARY_MODEL = "openrouter/this-model-does-not-exist-xyz"

REPORT_JSON_SCHEMA = {
    "type": "object",
    "properties": {
        "answer": {"type": "string"},
        "citations": {"type": "array", "items": {"type": "string"}},
    },
    "required": ["answer", "citations"],
    "additionalProperties": False,  # required for OpenAI strict json_schema mode
}

RESPONSE_FORMAT = {
    "type": "json_schema",
    "json_schema": {
        "name": "research_report",
        "strict": True,
        "schema": REPORT_JSON_SCHEMA,
    },
}


class OpenRouterError(RuntimeError):
    pass


def _request(path, payload=None, method="POST", timeout=60):
    if not API_KEY:
        raise OpenRouterError("OPENROUTER_API_KEY is not set in the environment")
    url = f"{OPENROUTER_BASE}{path}"
    data = json.dumps(payload).encode("utf-8") if payload is not None else None
    req = urllib.request.Request(url, data=data, method=method)
    # Single auth layer: only OpenRouter ever sees this key. Never forward a
    # separate provider credential for perplexity/openai — OpenRouter injects
    # provider auth server-side (same principle as the Nango proxy gotcha).
    req.add_header("Authorization", f"Bearer {API_KEY}")
    req.add_header("Content-Type", "application/json")
    # Optional attribution headers (not required for correctness):
    req.add_header("HTTP-Referer", "https://agent-university.local/poc")
    req.add_header("X-Title", "Agent University L-Capstone POC")
    try:
        with urllib.request.urlopen(req, timeout=timeout) as resp:
            return json.loads(resp.read().decode("utf-8"))
    except urllib.error.HTTPError as e:
        body = e.read().decode("utf-8", errors="replace")
        raise OpenRouterError(f"HTTP {e.code} calling {path}: {body}") from e
    except urllib.error.URLError as e:
        raise OpenRouterError(f"Network error calling {path}: {e}") from e


def chat_completion(model=None, models=None, messages=None, response_format=None):
    assert messages is not None
    payload = {"messages": messages}
    if models is not None:
        payload["models"] = models  # fallback chain: OpenRouter tries in order
    elif model is not None:
        payload["model"] = model
    else:
        raise ValueError("must supply model or models")
    if response_format is not None:
        payload["response_format"] = response_format
    return _request("/chat/completions", payload=payload, method="POST")


def get_generation(gen_id, max_retries=6, initial_delay=1.5):
    """GET /generation?id=... — cost/usage stats are not always available
    the instant a completion returns; retry with backoff on failure."""
    delay = initial_delay
    last_err = None
    for _ in range(max_retries):
        try:
            return _request(f"/generation?id={gen_id}", method="GET")
        except OpenRouterError as e:
            last_err = e
            time.sleep(delay)
            delay *= 1.5
    raise OpenRouterError(f"generation {gen_id} never became available: {last_err}")


def _extract_url_citations(message):
    citations = []
    for ann in (message.get("annotations") or []):
        if ann.get("type") == "url_citation":
            url = (ann.get("url_citation") or {}).get("url")
            if url:
                citations.append(url)
    return citations


def research_step(question):
    resp = chat_completion(
        model=RESEARCH_MODEL,
        messages=[{
            "role": "user",
            "content": (
                "Answer the following question using current web information. "
                f"Be concise and factual.\n\nQuestion: {question}"
            ),
        }],
    )
    message = resp["choices"][0]["message"]
    return {
        "raw_answer": message.get("content", ""),
        "citations": _extract_url_citations(message),
        "gen_id": resp["id"],
        "served_model": resp.get("model"),
    }


def structure_step(question, raw_answer, seed_citations):
    citation_hint = "\n".join(f"- {c}" for c in seed_citations) or "(none provided)"
    resp = chat_completion(
        model=SCHEMA_MODEL,
        response_format=RESPONSE_FORMAT,
        messages=[
            {
                "role": "system",
                "content": (
                    "You produce a strict JSON object with fields 'answer' "
                    "(string) and 'citations' (array of URL strings). Reuse "
                    "the given source URLs where relevant; do not invent new ones."
                ),
            },
            {
                "role": "user",
                "content": (
                    f"Question: {question}\n\n"
                    f"Draft answer from web research:\n{raw_answer}\n\n"
                    f"Source URLs:\n{citation_hint}\n\nReturn the JSON object now."
                ),
            },
        ],
    )
    parsed = json.loads(resp["choices"][0]["message"]["content"])
    return {
        "answer": parsed["answer"],
        "citations": parsed["citations"],
        "gen_id": resp["id"],
        "served_model": resp.get("model"),
    }


def fallback_structured_step(question):
    """Single-step fallback: fake primary fails, OpenRouter's `models` chain
    routes to gpt-4o-mini, which answers directly with the enforced schema
    (no web grounding, since the fake primary never returns)."""
    resp = chat_completion(
        models=[FAKE_PRIMARY_MODEL, SCHEMA_MODEL],
        response_format=RESPONSE_FORMAT,
        messages=[
            {
                "role": "system",
                "content": (
                    "You produce a strict JSON object with fields 'answer' "
                    "(string) and 'citations' (array of URL strings, may be empty)."
                ),
            },
            {"role": "user", "content": question},
        ],
    )
    parsed = json.loads(resp["choices"][0]["message"]["content"])
    return {
        "answer": parsed["answer"],
        "citations": parsed["citations"],
        "gen_id": resp["id"],
        "served_model": resp.get("model"),
    }


def _cost_record(gen_id):
    gen = get_generation(gen_id)
    data = gen.get("data", gen)  # response is nested under "data"
    return {
        "gen_id": gen_id,
        "total_cost": float(data.get("total_cost", 0.0)),
        "provider_name": data.get("provider_name"),
        "native_tokens_prompt": data.get("native_tokens_prompt"),
        "native_tokens_completion": data.get("native_tokens_completion"),
    }


@lru_cache(maxsize=None)
def run_pipeline(question):
    research = research_step(question)
    structured = structure_step(question, research["raw_answer"], research["citations"])

    cost_records = [_cost_record(research["gen_id"]), _cost_record(structured["gen_id"])]
    total_cost = sum(r["total_cost"] for r in cost_records)

    return {
        "question": question,
        "answer": structured["answer"],
        "citations": structured["citations"],
        "raw_answer": research["raw_answer"],
        "research_citations": research["citations"],
        "gen_ids": [r["gen_id"] for r in cost_records],
        "cost_records": cost_records,
        "total_cost": total_cost,
        "served_models": [research["served_model"], structured["served_model"]],
    }


@lru_cache(maxsize=None)
def run_fallback_pipeline(question):
    result = fallback_structured_step(question)
    cost = _cost_record(result["gen_id"])
    return {
        "question": question,
        "answer": result["answer"],
        "citations": result["citations"],
        "gen_id": result["gen_id"],
        "served_model": result["served_model"],
        "cost_record": cost,
        "total_cost": cost["total_cost"],
    }


def _print_report(title, data):
    print(f"\n=== {title} ===")
    print(json.dumps(data, indent=2, default=str))


if __name__ == "__main__":
    if not API_KEY:
        raise SystemExit("Set OPENROUTER_API_KEY before running the smoke test.")

    q = "What is the current population of Tokyo and what is its main international airport?"
    print(f"Question: {q}")

    result = run_pipeline(q)
    _print_report("Structured report", {
        "answer": result["answer"],
        "citations": result["citations"],
        "total_cost_usd": result["total_cost"],
        "served_models": result["served_models"],
    })

    fb = run_fallback_pipeline(q)
    _print_report("Forced-fallback report", {
        "answer": fb["answer"],
        "citations": fb["citations"],
        "served_model": fb["served_model"],
        "cost_usd": fb["total_cost"],
    })

    print(f"\nTotal spend this run: ${result['total_cost'] + fb['total_cost']:.6f}")
```

## `source/test_capstone.py`

```python
import unittest

from poc_capstone import run_pipeline, run_fallback_pipeline

QUESTION_1 = "What is the current population of Tokyo and what is its main international airport?"
QUESTION_2 = "What year was the Python programming language first released and who created it?"


class TestSchemaValidReport(unittest.TestCase):
    @classmethod
    def setUpClass(cls):
        cls.result = run_pipeline(QUESTION_1)

    def test_answer_nonempty(self):
        self.assertTrue(len(self.result["answer"].strip()) > 0)

    def test_citations_present(self):
        self.assertGreaterEqual(len(self.result["citations"]), 1)

    def test_citations_are_strings(self):
        for c in self.result["citations"]:
            self.assertIsInstance(c, str)


class TestRealCostAccounting(unittest.TestCase):
    @classmethod
    def setUpClass(cls):
        cls.result = run_pipeline(QUESTION_1)

    def test_total_cost_positive(self):
        self.assertGreater(self.result["total_cost"], 0.0)

    def test_gen_ids_prefixed(self):
        for gid in self.result["gen_ids"]:
            self.assertTrue(gid.startswith("gen-"), gid)

    def test_provider_name_present(self):
        for rec in self.result["cost_records"]:
            self.assertTrue(rec["provider_name"])


class TestFallbackRouting(unittest.TestCase):
    @classmethod
    def setUpClass(cls):
        cls.fallback_result = run_fallback_pipeline(QUESTION_1)

    def test_fallback_valid_schema(self):
        self.assertTrue(len(self.fallback_result["answer"].strip()) > 0)
        self.assertIsInstance(self.fallback_result["citations"], list)

    def test_served_model_is_the_real_fallback(self):
        served = self.fallback_result["served_model"]
        self.assertNotEqual(served, "openrouter/this-model-does-not-exist-xyz")
        self.assertIn("gpt-4o-mini", served)


class TestCostSumming(unittest.TestCase):
    @classmethod
    def setUpClass(cls):
        cls.result = run_pipeline(QUESTION_1)

    def test_sum_matches_records(self):
        summed = sum(r["total_cost"] for r in self.result["cost_records"])
        self.assertAlmostEqual(summed, self.result["total_cost"], places=8)

    def test_at_least_two_gen_ids(self):
        self.assertGreaterEqual(len(self.result["gen_ids"]), 2)


class TestRegression(unittest.TestCase):
    @classmethod
    def setUpClass(cls):
        cls.result = run_pipeline(QUESTION_2)
        cls.fallback_result = run_fallback_pipeline(QUESTION_2)

    def test_schema_valid(self):
        self.assertTrue(len(self.result["answer"].strip()) > 0)
        self.assertGreaterEqual(len(self.result["citations"]), 1)

    def test_cost_nonzero(self):
        self.assertGreater(self.result["total_cost"], 0.0)

    def test_fallback_still_works(self):
        self.assertTrue(len(self.fallback_result["answer"].strip()) > 0)


