### `/tmp/agentcn-Lcapstone/registry/eve/au-advisor/tools/get-travel-weather.ts`

```ts
// [INFERRED import path] — package name assumed to be "eve" since the CLI is
// invoked as `npx eve build` / `npx eve start`. Confirm against the actual
// exported entrypoints in the cloned repo (`grep -r "defineTool" node_modules/eve`)
// before treating this as gospel.
import { defineTool } from "eve";
import { z } from "zod";

// Real, keyless Open-Meteo geocoding + forecast APIs. No API key required.
const GEOCODE_URL = "https://geocoding-api.open-meteo.com/v1/search";
const FORECAST_URL = "https://api.open-meteo.com/v1/forecast";

export const getTravelWeather = defineTool({
  name: "get_travel_weather",
  description:
    "Look up REAL current weather conditions for a destination city " +
    "(temperature, feels-like temperature, precipitation, wind) to give " +
    "grounded travel packing advice. You MUST call this before recommending " +
    "what to pack — never guess the weather.",
  parameters: z.object({
    city: z.string().describe("Destination city name, e.g. 'Seoul'"),
  }),
  async execute({ city }) {
    // Step 1: geocode city -> lat/lon (real Open-Meteo call, no mock)
    const geoRes = await fetch(
      `${GEOCODE_URL}?name=${encodeURIComponent(city)}&count=1&language=en&format=json`
    );
    if (!geoRes.ok) {
      throw new Error(`Open-Meteo geocoding failed: ${geoRes.status}`);
    }
    const geoJson = await geoRes.json();
    const hit = geoJson.results?.[0];
    if (!hit) {
      throw new Error(`No geocoding match for city: ${city}`);
    }
    const { latitude, longitude, name, country } = hit;

    // Step 2: current forecast for that lat/lon (real Open-Meteo call)
    const params = new URLSearchParams({
      latitude: String(latitude),
      longitude: String(longitude),
      current:
        "temperature_2m,apparent_temperature,precipitation,wind_speed_10m,weather_code",
      timezone: "auto",
    });
    const fRes = await fetch(`${FORECAST_URL}?${params.toString()}`);
    if (!fRes.ok) {
      throw new Error(`Open-Meteo forecast failed: ${fRes.status}`);
    }
    const fJson = await fRes.json();
    const cur = fJson.current;

    return {
      city: name,
      country,
      temperature_c: cur.temperature_2m,
      feels_like_c: cur.apparent_temperature,
      precipitation_mm: cur.precipitation,
      wind_speed_kmh: cur.wind_speed_10m,
      weather_code: cur.weather_code,
      fetched_at: cur.time,
    };
  },
});
```

