## 3. NDJSON session driver / assertions

### `source/assert.mjs`

```js
#!/usr/bin/env node
// Drives the NDJSON session API of a running `eve start` process and
// checks either the GREEN 6-assertion path or the RED 401 failure path.
//
// [INFERRED HTTP surface] — route paths /api/sessions and
// /api/sessions/:id/messages, and the request/response shapes below, are
// reconstructed from the event vocabulary given in the POC spec, not from
// a documented Eve HTTP spec. On first real run: log raw NDJSON lines
// BEFORE trusting the field-name lookups below (evt.toolName vs
// evt.tool_name, requested.arguments vs requested.input, etc.) and patch
// this file if the real runtime differs.

const port = process.argv.includes("--port")
  ? process.argv[process.argv.indexOf("--port") + 1]
  : "3888";
const base = `http://127.0.0.1:${port}`;
const mode = process.argv.includes("--expect-red") ? "red" : "green";

async function driveSession() {
  const createRes = await fetch(`${base}/api/sessions`, {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify({ agentId: "au-advisor" }),
  });
  if (!createRes.ok) {
    throw new Error(
      `session create failed: ${createRes.status} ${await createRes.text()}`
    );
  }
  const { sessionId } = await createRes.json();

  const streamRes = await fetch(`${base}/api/sessions/${sessionId}/messages`, {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify({
      prompt:
        "I'm traveling to Seoul next week. What should I pack? " +
        "Check current conditions with your weather tool before answering.",
    }),
  });

  const events = [];
  const reader = streamRes.body.getReader();
  const decoder = new TextDecoder();
  let buf = "";
  while (true) {
    const { value, done } = await reader.read();
    if (done) break;
    buf += decoder.decode(value, { stream: true });
    let idx;
    while ((idx = buf.indexOf("\n")) >= 0) {
      const line = buf.slice(0, idx).trim();
      buf = buf.slice(idx + 1);
      if (!line) continue;
      const evt = JSON.parse(line);
      events.push(evt);
      console.log(`[event] ${JSON.stringify(evt).slice(0, 300)}`);
    }
  }
  if (buf.trim()) events.push(JSON.parse(buf.trim()));
  return events;
}

function assertGreen(events) {
  const started = events.find((e) => e.type === "session.started");
  if (!started || started.modelId !== "anthropic/claude-sonnet-4.6") {
    throw new Error(`A1 FAILED: modelId=${started?.modelId}`);
  }
  console.log("A1 PASS: session.started modelId=anthropic/claude-sonnet-4.6");

  const requested = events.find(
    (e) => e.type === "actions.requested" && e.toolName === "get_travel_weather"
  );
  if (!requested) throw new Error("A2 FAILED: no actions.requested for get_travel_weather");
  console.log("A2 PASS: actions.requested toolName=get_travel_weather");

  const args = requested.arguments ?? requested.input;
  if (!args || args.city !== "Seoul") {
    throw new Error(`A3 FAILED: tool called with city=${args?.city}`);
  }
  console.log("A3 PASS: tool called with city=Seoul");

  const result = events.find((e) => e.type === "action.result");
  const temp = result?.output?.temperature_c ?? result?.result?.temperature_c;
  if (typeof temp !== "number") {
    throw new Error("A4 FAILED: action.result missing numeric temperature_c");
  }
  console.log(`A4 PASS: action.result temperature_c=${temp}°C (live Open-Meteo)`);

  const completed = events.find((e) => e.type === "message.completed");
  const text = completed?.content ?? completed?.message?.content ?? "";
  if (!completed || typeof text !== "string" || text.length === 0) {
    throw new Error("A5 FAILED: message.completed missing/empty content");
  }
  console.log("A5 PASS: message.completed with non-empty packing advice");
  console.log(`         "${text.slice(0, 160)}..."`);

  if (!events.find((e) => e.type === "session.waiting")) {
    throw new Error("A6 FAILED: no terminal session.waiting event");
  }
  console.log("A6 PASS: session.waiting terminal event observed");
  console.log("\nALL 6 ASSERTIONS PASS (GREEN)");
}

function assertRed(events) {
  const failed = events.find((e) => e.type === "step.failed");
  if (
    !failed ||
    failed.error?.name !== "GatewayAuthenticationError" ||
    failed.error?.statusCode !== 401
  ) {
    throw new Error(
      `RED assertion FAILED: expected step.failed/GatewayAuthenticationError/401, got ${JSON.stringify(failed)}`
    );
  }
  console.log("RED PASS: step.failed GatewayAuthenticationError statusCode=401");
}

const events = await driveSession();
mode === "red" ? assertRed(events) : assertGreen(events);
```

