### `source/src/taskStore.ts` (L14 — real external store)

```ts
import { useSyncExternalStore } from "react";

export type Task = {
  id: string;
  title: string;
  done: boolean;
};

type Listener = () => void;

class TaskStore {
  private tasks: Task[] = [];
  private listeners = new Set<Listener>();

  subscribe = (listener: Listener) => {
    this.listeners.add(listener);
    return () => {
      this.listeners.delete(listener);
    };
  };

  getSnapshot = (): Task[] => this.tasks;

  setTasks = (tasks: Task[]) => {
    this.tasks = tasks;
    this.emit();
  };

  addTask = (task: Task) => {
    this.tasks = [...this.tasks, task];
    this.emit();
  };

  updateTask = (id: string, patch: Partial<Task>) => {
    this.tasks = this.tasks.map((t) => (t.id === id ? { ...t, ...patch } : t));
    this.emit();
  };

  private emit() {
    this.listeners.forEach((l) => l());
  }
}

export const taskStore = new TaskStore();

/** L14: real useSyncExternalStore subscription — no mock store. */
export function useTaskStore(): Task[] {
  return useSyncExternalStore(
    taskStore.subscribe,
    taskStore.getSnapshot,
    taskStore.getSnapshot
  );
}
```

