```tsx
import { useActionState, useId, useRef } from "react";
import { useFormStatus } from "react-dom";

type FormState = { error: string | null };

type Props = {
  onAddOptimistic: (title: string) => void;
  onCommit: (title: string) => Promise<void>;
};

function SubmitButton() {
  const { pending } = useFormStatus();
  return (
    <button type="submit" disabled={pending} data-testid="submit-add">
      {pending ? "Adding..." : "Add Task"}
    </button>
  );
}

export function AddTaskForm({ onAddOptimistic, onCommit }: Props) {
  const inputId = useId();
  const formRef = useRef<HTMLFormElement>(null);

  const [state, formAction] = useActionState<FormState, FormData>(
    async (_prevState, formData) => {
      const title = String(formData.get("title") ?? "");

      // L19: instant optimistic entry before the request resolves.
      onAddOptimistic(title);
      formRef.current?.reset();

      try {
        await onCommit(title);
        return { error: null };
      } catch (err) {
        return { error: err instanceof Error ? err.message : "Failed to add task" };
      }
    },
    { error: null }
  );

  return (
    <form ref={formRef} action={formAction}>
      <label htmlFor={inputId}>New task</label>
      <input id={inputId} name="title" type="text" data-testid="new-task-input" />
      <SubmitButton />
      {state.error && <p role="alert">{state.error}</p>}
    </form>
  );
}
```

