// Shared pg.Pool + pgvector type registration (L12 concept, reused by L21).
import pg from 'pg';
import pgvector from 'pgvector/pg';

let pool;

export function getPool() {
  if (!pool) {
    pool = new pg.Pool({
      host: process.env.PGV_HOST || '127.0.0.1',
      port: Number(process.env.PGV_PORT || 5441),
      user: process.env.PGV_USER || 'postgres',
      password: process.env.PGV_PASSWORD,
      database: process.env.PGV_DATABASE || 'pgv_capstone',
    });

    // Register the vector/halfvec type codec on every new physical connection
    // the pool opens, so pg can (de)serialize halfvec columns transparently.
    pool.on('connect', async (client) => {
      await pgvector.registerType(client);
    });
  }
  return pool;
}

export async function closePool() {
  if (pool) {
    await pool.end();
    pool = undefined;
  }
}
