## `03-pocs/L21-capstone-semantic-search-service/source/service.mjs`

```js
// SearchService — the exportable mini-service the capstone POC must prove.
//
// Combines:
//   L04/L08  HNSW index over halfvec(256), halfvec_cosine_ops
//   L14      OpenAI text-embedding-3-small (dims=256) for ingest + query
//   L15      tsvector GIN generated column + RRF fusion of semantic/lexical arms
//   L16      category metadata filter + hnsw.iterative_scan for no under-return
//   L18      failure-mode guards (bad input rejected up front; missing-table
//            errors are NOT swallowed — they propagate as real pg errors)
//   L19      EXPLAIN-based observability (explainSemanticArm)

const VALID_ITERATIVE_SCAN = new Set(['off', 'relaxed_order', 'strict_order']);

export class SearchService {
  /**
   * @param {import('pg').Pool} pool
   * @param {(text: string) => Promise<number[]>} embed
   */
  constructor(pool, embed) {
    this.pool = pool;
    this.embed = embed;
  }

  /**
   * Hybrid (semantic + lexical, RRF-fused) retrieval.
   *
   * @param {string} query
   * @param {object} [opts]
   * @param {string|null} [opts.category] - optional category pre-filter
   * @param {number} [opts.limit=5]
   * @param {number} [opts.efSearch=100] - HNSW ef_search (recall/speed tuning)
   * @param {'off'|'relaxed_order'|'strict_order'} [opts.iterativeScan='relaxed_order']
   *   pgvector's actual GUC values (NOT "on" — that value does not exist and
   *   Postgres will throw `invalid value for parameter "hnsw.iterative_scan"`).
   *   `relaxed_order` lets HNSW keep scanning past filtered-out candidates so
   *   the requested LIMIT is still satisfied when a category filter is applied.
   * @param {number} [opts.k=60] - RRF fusion constant (1/(k+rank))
   */
  async retrieve(query, opts = {}) {
    if (typeof query !== 'string' || query.trim() === '') {
      throw new Error('retrieve(query): query must be a non-empty string');
    }
    if (opts.category != null && typeof opts.category !== 'string') {
      throw new Error('retrieve(query, { category }): category must be a string or null');
    }

    const {
      category = null,
      limit = 5,
      efSearch = 100,
      iterativeScan = 'relaxed_order',
      k = 60,
    } = opts;

    if (!VALID_ITERATIVE_SCAN.has(iterativeScan)) {
      throw new Error(
        `retrieve(): invalid iterativeScan "${iterativeScan}". ` +
        `pgvector only accepts: ${[...VALID_ITERATIVE_SCAN].join(', ')}`
      );
    }

    const embedding = await this.embed(query);
    const vectorLiteral = `[${embedding.join(',')}]`;

    const client = await this.pool.connect();
    try {
      // Session-level GUCs must be set on the SAME connection that runs the
      // query (pg.Pool hands out arbitrary physical connections per checkout).
      await client.query(`SET hnsw.ef_search = ${Number(efSearch)}`);
      await client.query(`SET hnsw.iterative_scan = '${iterativeScan}'`);

      const sql = `
        WITH semantic_ranked AS (
          SELECT id, row_number() OVER (ORDER BY embedding <=> $1::halfvec) AS rank
          FROM documents
          WHERE ($2::text IS NULL OR category = $2::text)
          ORDER BY embedding <=> $1::halfvec
          LIMIT $3
        ),
        lexical_ranked AS (
          SELECT id, row_number() OVER (
            ORDER BY ts_rank(body_tsv, websearch_to_tsquery('english', $4)) DESC
          ) AS rank
          FROM documents
          WHERE ($2::text IS NULL OR category = $2::text)
            AND body_tsv @@ websearch_to_tsquery('english', $4)
          ORDER BY ts_rank(body_tsv, websearch_to_tsquery('english', $4)) DESC
          LIMIT $3
        )
        SELECT
          d.id, d.title, d.body, d.category,
          COALESCE(1.0 / ($5 + s.rank), 0) + COALESCE(1.0 / ($5 + l.rank), 0) AS rrf_score
        FROM documents d
        LEFT JOIN semantic_ranked s ON s.id = d.id
        LEFT JOIN lexical_ranked  l ON l.id = d.id
        WHERE s.id IS NOT NULL OR l.id IS NOT NULL
        ORDER BY rrf_score DESC
        LIMIT $3
      `;

      const { rows } = await client.query(sql, [vectorLiteral, category, limit, query, k]);
      return rows;
    } finally {
      // NOTE: no try/catch around the query above — a missing `documents`
      // table (or any other real pg error) propagates unmodified. This is
      // the L18 "failure-mode guard": the guard is *not swallowing* the error.
      client.release();
    }
  }

  /**
   * EXPLAIN observability for the semantic arm only (L19).
   * Returns the raw EXPLAIN text plan lines.
   */
  async explainSemanticArm(query, opts = {}) {
    const { limit = 5, efSearch = 100 } = opts;
    const embedding = await this.embed(query);
    const vectorLiteral = `[${embedding.join(',')}]`;

    const client = await this.pool.connect();
    try {
      await client.query(`SET hnsw.ef_search = ${Number(efSearch)}`);
      const { rows } = await client.query(
        `EXPLAIN SELECT id FROM documents ORDER BY embedding <=> $1::halfvec LIMIT $2`,
        [vectorLiteral, limit]
      );
      return rows.map((r) => r['QUERY PLAN']);
    } finally {
      client.release();
    }
  }
}
```

