export async function bootstrapFga(): Promise<FgaContext> {
  const bootstrap = new OpenFgaClient({ apiUrl: API_URL });
  const store = await bootstrap.createStore({
    name: `secure-doc-assistant-${Date.now()}`,
  });

  const client = new OpenFgaClient({ apiUrl: API_URL, storeId: store.id });
  const { authorization_model_id } = await client.writeAuthorizationModel(MODEL);

  await seedTuples(client, authorization_model_id);

  return { client, storeId: store.id, authorizationModelId: authorization_model_id };
}

async function seedTuples(client: OpenFgaClient, authorizationModelId: string) {
  await client.write(
    {
      writes: [
        // group membership
        { user: 'user:alice', relation: 'member', object: 'group:exec' },
        { user: 'user:alice', relation: 'member', object: 'group:eng' },
        { user: 'user:bob', relation: 'member', object: 'group:eng' },

        // document:acquisition — exec-only viewer, alice owns it
        { user: 'user:alice', relation: 'owner', object: 'document:acquisition' },
        { user: 'group:exec#member', relation: 'viewer', object: 'document:acquisition' },

        // document:roadmap — eng-visible, alice owns it (bob is viewer, NOT owner/sharer)
        { user: 'user:alice', relation: 'owner', object: 'document:roadmap' },
        { user: 'group:eng#member', relation: 'viewer', object: 'document:roadmap' },

        // document:handbook — eng-visible, alice owns it
        { user: 'user:alice', relation: 'owner', object: 'document:handbook' },
        { user: 'group:eng#member', relation: 'viewer', object: 'document:handbook' },
      ],
    },
    { authorizationModelId }
  );
}

export async function checkViewer(
  ctx: FgaContext,
  user: string,
  documentId: string
): Promise<boolean> {
  const { allowed } = await ctx.client.check(
    { user: `user:${user}`, relation: 'viewer', object: documentId },
    { authorizationModelId: ctx.authorizationModelId }
  );
  return Boolean(allowed);
}

/** Pure ground-truth check — always hits the real /check endpoint, no gating. */
export async function checkCanShare(
  ctx: FgaContext,
  user: string,
  documentId: string
): Promise<boolean> {
  const { allowed } = await ctx.client.check(
    { user: `user:${user}`, relation: 'can_share', object: documentId },
    { authorizationModelId: ctx.authorizationModelId }
  );
  return Boolean(allowed);
}

/** batchCheck(viewer) across the whole corpus for the current user. */
export async function filterViewableDocs(
  ctx: FgaContext,
  user: string,
  documentIds: string[]
): Promise<string[]> {
  const checks = documentIds.map((object) => ({
    user: `user:${user}`,
    relation: 'viewer',
    object,
    // OpenFGA batch-check correlationIds must be [a-zA-Z0-9_-]+
    correlationId: object.replace(/[^a-zA-Z0-9_-]/g, '_'),
  }));

  try {
    const response: any = await (ctx.client as any).batchCheck(
      { checks },
      { authorizationModelId: ctx.authorizationModelId }
    );
    const byCorrelation = new Map(checks.map((c) => [c.correlationId, c.object]));
    const allowedIds = (response.result ?? [])
      .filter((r: any) => r.allowed)
      .map((r: any) => byCorrelation.get(r.correlationId))
      .filter(Boolean) as string[];
    return documentIds.filter((id) => allowedIds.includes(id));
  } catch {
    // Defensive fallback if this SDK build's batchCheck surface differs —
    // functionally equivalent parallel /check calls.
    const results = await Promise.all(
      documentIds.map(async (object) => ({
        object,
        allowed: await checkViewer(ctx, user, object),
      }))
    );
    return results.filter((r) => r.allowed).map((r) => r.object);
  }
}

export async function grantViewer(
  ctx: FgaContext,
  targetUser: string,
  documentId: string
): Promise<void> {
  await ctx.client.write(
    { writes: [{ user: `user:${targetUser}`, relation: 'viewer', object: documentId }] },
    { authorizationModelId: ctx.authorizationModelId }
  );
}
