```ts
import type { FgaContext } from './fga.js';
import { filterViewableDocs, checkCanShare, grantViewer } from './fga.js';
import { CORPUS, ALL_DOC_IDS } from './corpus.js';
import type { AuditLog } from './audit.js';

export const TOOL_DEFINITIONS = [
  {
    name: 'search_docs',
    description:
      'Search the internal document corpus. Only documents the CURRENT user is authorized ' +
      'to view (FGA "viewer" relation) are ever returned as context.',
    input_schema: {
      type: 'object',
      properties: { query: { type: 'string' } },
      required: ['query'],
    },
  },
  {
    name: 'share_document',
    description:
      'Grant another user viewer access to a document. Requires the current user to hold ' +
      '"can_share" on that document (owner-only). Non-owners are refused.',
    input_schema: {
      type: 'object',
      properties: {
        documentId: { type: 'string', description: 'e.g. document:roadmap' },
        targetUser: { type: 'string', description: 'e.g. dave' },
      },
      required: ['documentId', 'targetUser'],
    },
  },
] as const;

export function makeToolExecutor(ctx: FgaContext, currentUser: string, audit: AuditLog) {
  return async function executeTool(name: string, input: any): Promise<string> {
    const start = Date.now();

    if (name === 'search_docs') {
      const viewableIds = await filterViewableDocs(ctx, currentUser, ALL_DOC_IDS);

      audit.record({
        timestamp: new Date().toISOString(),
        user: currentUser,
        tool: 'search_docs',
        object: ALL_DOC_IDS.join(','),
        fga_decision: viewableIds.length > 0,
        latency_ms: Date.now() - start,
      });

      if (viewableIds.length === 0) {
        return 'No documents are visible to the current user for this query.';
      }
      return viewableIds
        .map((id) => `[${id}] ${CORPUS[id].title}: ${CORPUS[id].content}`)
        .join('\n');
    }

    if (name === 'share_document') {
      const { documentId, targetUser } = input;

      // GATE_SHARE=0 == the vulnerability under test: the app forgets to call
      // the authorization check at all and just performs the write. This is
      // read at call-time, not module load, so tests can toggle it per run.
      const gateEnabled = process.env.GATE_SHARE !== '0';
      const allowed = gateEnabled ? await checkCanShare(ctx, currentUser, documentId) : true;

      audit.record({
        timestamp: new Date().toISOString(),
        user: currentUser,
        tool: 'share_document',
        object: documentId,
        fga_decision: allowed,
        latency_ms: Date.now() - start,
      });

      if (!allowed) {
        return `DENIED: ${currentUser} does not have permission to share ${documentId}. Only the document owner can share it.`;
      }

      await grantViewer(ctx, targetUser, documentId);
      return `OK: ${documentId} shared with ${targetUser}. They now have viewer access.`;
    }

    throw new Error(`Unknown tool: ${name}`);
  };
}
