## `source/pricing.mjs`

```js
// pricing.mjs
// Nano-USD (1e-9 USD) per token. VERIFY against https://fireworks.ai/pricing
// before trusting cost_usd for real chargeback — these numbers are illustrative
// and must be refreshed if Fireworks changes serverless pricing.
// The gateway 400s any request whose model has no entry here (see priceFor()).
export const PRICE_TABLE = {
  'accounts/fireworks/models/gpt-oss-20b': {
    promptNanoPerToken: 50,       // $0.05 / 1M input tokens
    cachedNanoPerToken: 10,       // discounted cache-hit rate (illustrative)
    completionNanoPerToken: 200,  // $0.20 / 1M output tokens
  },
};

export function priceFor(model) {
  const p = PRICE_TABLE[model];
  if (!p) {
    const err = new Error(`No price entry for model "${model}" in PRICE_TABLE`);
    err.status = 400;
    throw err;
  }
  return p;
}

export function computeCostNano(model, usage) {
  const p = priceFor(model);
  const cached = usage?.prompt_tokens_details?.cached_tokens ?? 0;
  const uncachedPrompt = Math.max(0, (usage?.prompt_tokens ?? 0) - cached);
  const completion = usage?.completion_tokens ?? 0;
  const nano =
    uncachedPrompt * p.promptNanoPerToken +
    cached * p.cachedNanoPerToken +
    completion * p.completionNanoPerToken;
  return Math.round(nano);
}
```

## `source/store.mjs`

```js
// store.mjs — in-memory control-plane store.
// NOTE: single-process, non-persistent. Fine for the capstone POC; a real
// multi-tenant deployment needs a durable store (Postgres/Redis) behind this
// same interface.
import { randomUUID, randomBytes } from 'node:crypto';

const tenants = new Map();     // tenantId -> tenant record
const keyToTenant = new Map(); // apiKey -> tenantId

export function createTenant({ name, tokenLimit = Infinity }) {
  const tenantId = randomUUID();
  const apiKey = `tk_${randomBytes(24).toString('hex')}`;
  const tenant = {
    id: tenantId,
    name,
    apiKey,
    tokenLimit,
    usage: {
      calls: 0,
      prompt_tokens: 0,
      completion_tokens: 0,
      cached_tokens: 0,
      total_tokens: 0,
      cost_nano: 0,
    },
    byModel: new Map(),
  };
  tenants.set(tenantId, tenant);
  keyToTenant.set(apiKey, tenantId);
  return { tenantId, apiKey };
}

export function tenantByKey(apiKey) {
  const id = keyToTenant.get(apiKey);
  return id ? tenants.get(id) : undefined;
}

export function tenantById(tenantId) {
  return tenants.get(tenantId);
}

export function tokensUsedSoFar(tenant) {
  return tenant.usage.total_tokens;
}

export function recordUsage(tenant, { model, usage, costNano }) {
  tenant.usage.calls += 1;
  tenant.usage.prompt_tokens += usage.prompt_tokens ?? 0;
  tenant.usage.completion_tokens += usage.completion_tokens ?? 0;
  tenant.usage.cached_tokens += usage.prompt_tokens_details?.cached_tokens ?? 0;
  tenant.usage.total_tokens += usage.total_tokens ?? 0;
  tenant.usage.cost_nano += costNano;

  const perModel = tenant.byModel.get(model) ?? {
    calls: 0, prompt_tokens: 0, completion_tokens: 0, total_tokens: 0, cost_nano: 0,
  };
  perModel.calls += 1;
  perModel.prompt_tokens += usage.prompt_tokens ?? 0;
  perModel.completion_tokens += usage.completion_tokens ?? 0;
  perModel.total_tokens += usage.total_tokens ?? 0;
  perModel.cost_nano += costNano;
  tenant.byModel.set(model, perModel);
}

export function usageReport(tenant) {
  return {
    calls: tenant.usage.calls,
    prompt_tokens: tenant.usage.prompt_tokens,
    completion_tokens: tenant.usage.completion_tokens,
    cached_tokens: tenant.usage.cached_tokens,
    total_tokens: tenant.usage.total_tokens,
    cost_nano: tenant.usage.cost_nano,
    cost_usd: (tenant.usage.cost_nano / 1e9).toFixed(6),
    by_model: Object.fromEntries(
      [...tenant.byModel.entries()].map(([model, v]) => [
        model,
        { ...v, cost_usd: (v.cost_nano / 1e9).toFixed(6) },
      ]),
    ),
  };
}

// test-only reset hook (not used by the live socket path, only useful for
// isolated unit tests of store.mjs itself)
export function __resetForTests() {
  tenants.clear();
  keyToTenant.clear();
}
