// upstream.mjs — real Fireworks call, OpenAI-compatible chat/completions.
// Docs: https://docs.fireworks.ai/api-reference/post-chatcompletions
const FIREWORKS_BASE_URL =
  process.env.FIREWORKS_BASE_URL || 'https://api.fireworks.ai/inference/v1';

export async function callUpstreamChatCompletion(body) {
  const apiKey = process.env.FIREWORKS_API_KEY;
  if (!apiKey) {
    const err = new Error('FIREWORKS_API_KEY is not set in the environment');
    err.status = 500;
    throw err;
  }

  const res = await fetch(`${FIREWORKS_BASE_URL}/chat/completions`, {
    method: 'POST',
    headers: {
      'content-type': 'application/json',
      // Never log this header verbatim — see capstone.test.mjs step 5
      // (no-upstream-key-leak grep).
      authorization: `Bearer ${apiKey}`,
    },
    body: JSON.stringify(body),
  });

  const json = await res.json();
  if (!res.ok) {
    const err = new Error(json?.error?.message || `Fireworks upstream error ${res.status}`);
    err.status = res.status;
    err.body = json;
    throw err;
  }
  return json; // { id: "chatcmpl-...", usage: {...}, choices: [...], ... }
}
