## `source/gateway.mjs`

```js
// gateway.mjs — the whole control plane. Feature-complete from L0; every
// POC level exercises a different slice of this same file over a growing
// transport (in-process handle() -> real node:http socket at L5).
import { createServer } from 'node:http';
import {
  createTenant,
  tenantByKey,
  tenantById,
  tokensUsedSoFar,
  recordUsage,
  usageReport,
} from './store.mjs';
import { callUpstreamChatCompletion } from './upstream.mjs';
import { computeCostNano } from './pricing.mjs';

const ADMIN_KEY = process.env.GATEWAY_ADMIN_KEY || 'admin-dev-key';

async function readJsonBody(req) {
  const chunks = [];
  for await (const chunk of req) chunks.push(chunk);
  const raw = Buffer.concat(chunks).toString('utf8');
  return raw ? JSON.parse(raw) : {};
}

function sendJson(res, status, body, extraHeaders = {}) {
  res.writeHead(status, { 'content-type': 'application/json', ...extraHeaders });
  res.end(JSON.stringify(body));
}

export const gw = {
  async handle(req, res) {
    try {
      const url = new URL(req.url, 'http://localhost');

      // --- Admin: issue a tenant key ---
      if (req.method === 'POST' && url.pathname === '/v1/admin/tenants') {
        if (req.headers['x-admin-key'] !== ADMIN_KEY) {
          return sendJson(res, 401, { error: 'unauthorized' });
        }
        const { name, tokenLimit } = await readJsonBody(req);
        const created = createTenant({ name, tokenLimit: tokenLimit ?? Infinity });
        return sendJson(res, 200, created);
      }

      // --- Admin: usage + cost report ---
      const usageMatch = url.pathname.match(/^\/v1\/admin\/tenants\/([^/]+)\/usage$/);
      if (req.method === 'GET' && usageMatch) {
        if (req.headers['x-admin-key'] !== ADMIN_KEY) {
          return sendJson(res, 401, { error: 'unauthorized' });
        }
        const tenant = tenantById(usageMatch[1]);
        if (!tenant) return sendJson(res, 404, { error: 'tenant not found' });
        return sendJson(res, 200, usageReport(tenant));
      }

      // --- Tenant: proxied chat completion ---
      if (req.method === 'POST' && url.pathname === '/v1/chat/completions') {
        const apiKey = (req.headers['authorization'] || '').replace(/^Bearer\s+/i, '');
        const tenant = tenantByKey(apiKey);
        if (!tenant) return sendJson(res, 401, { error: 'invalid tenant key' });

        // Cap check happens BEFORE the upstream call — a capped tenant is
        // never billed for a blocked request.
        if (tokensUsedSoFar(tenant) >= tenant.tokenLimit) {
          return sendJson(res, 429, {
            error: 'tenant token cap exceeded',
            tokenLimit: tenant.tokenLimit,
          });
        }

        const body = await readJsonBody(req);
        const upstream = await callUpstreamChatCompletion(body);
        const costNano = computeCostNano(body.model, upstream.usage);
        recordUsage(tenant, { model: body.model, usage: upstream.usage, costNano });

        return sendJson(res, 200, upstream, { 'x-gateway-cost-nano': String(costNano) });
      }

      return sendJson(res, 404, { error: 'not found' });
    } catch (err) {
      // Never let upstream error bodies leak the Authorization header we sent.
      const status = err.status ?? 500;
      return sendJson(res, status, { error: err.message });
    }
  },
};

export function serve(gateway, port = 0) {
  const server = createServer((req, res) => gateway.handle(req, res));
  return new Promise((resolve) => server.listen(port, () => resolve(server)));
}
```

