// capstone.test.mjs — L5: everything over a real node:http socket, real
// Fireworks traffic. This is the only file that grows at L5; the four
// modules above are byte-identical to L0–L4.
import { test } from 'node:test';
import assert from 'node:assert/strict';
import { gw, serve } from './gateway.mjs';

const ADMIN_KEY = process.env.GATEWAY_ADMIN_KEY || 'admin-dev-key';
const MODEL = 'accounts/fireworks/models/gpt-oss-20b';

test('L5 capstone: full multi-tenant gateway over a real socket', async (t) => {
  const server = await serve(gw, 0);
  const { port } = server.address();
  const base = `http://127.0.0.1:${port}`;
  t.after(() => server.close());

  // 1. Admin issues two tenant keys over HTTP
  const createA = await fetch(`${base}/v1/admin/tenants`, {
    method: 'POST',
    headers: { 'content-type': 'application/json', 'x-admin-key': ADMIN_KEY },
    body: JSON.stringify({ name: 'team-a' }),
  });
  assert.strictEqual(createA.status, 200);
  const teamA = await createA.json();

  const createB = await fetch(`${base}/v1/admin/tenants`, {
    method: 'POST',
    headers: { 'content-type': 'application/json', 'x-admin-key': ADMIN_KEY },
    body: JSON.stringify({ name: 'team-b', tokenLimit: 5 }),
  });
  assert.strictEqual(createB.status, 200);
  const teamB = await createB.json();

  const chatReq = {
    model: MODEL,
    messages: [{ role: 'user', content: 'Say "capstone" and nothing else.' }],
  };

  // 2. team-a: real Fireworks call over the socket
  const teamACall = await fetch(`${base}/v1/chat/completions`, {
    method: 'POST',
    headers: { 'content-type': 'application/json', authorization: `Bearer ${teamA.apiKey}` },
    body: JSON.stringify(chatReq),
  });
  assert.strictEqual(teamACall.status, 200);
  const teamAResponseBody = await teamACall.json();
  assert.match(teamAResponseBody.id, /^chatcmpl-/);
  const costNanoHeader = Number(teamACall.headers.get('x-gateway-cost-nano'));
  assert.ok(costNanoHeader > 0, 'x-gateway-cost-nano must be present and > 0');

  // 3. team-b (tokenLimit: 5): first call 200, second call blocked
  const teamBCall1 = await fetch(`${base}/v1/chat/completions`, {
    method: 'POST',
    headers: { 'content-type': 'application/json', authorization: `Bearer ${teamB.apiKey}` },
    body: JSON.stringify(chatReq),
  });
  assert.strictEqual(teamBCall1.status, 200);

  const teamBCall2 = await fetch(`${base}/v1/chat/completions`, {
    method: 'POST',
    headers: { 'content-type': 'application/json', authorization: `Bearer ${teamB.apiKey}` },
    body: JSON.stringify(chatReq),
  });
  const expectedSecondCallStatus = process.env.GATEWAY_RED === '1' ? 200 : 429;
  assert.strictEqual(
    teamBCall2.status,
    expectedSecondCallStatus,
    'team-b over token cap -> 429 (RED asserts 200)',
  );
  console.log('team-b capped:', teamBCall2.status);

  // 4. Usage+cost report (admin reads team-a)
  const reportRes = await fetch(`${base}/v1/admin/tenants/${teamA.tenantId}/usage`, {
    headers: { 'x-admin-key': ADMIN_KEY },
  });
  assert.strictEqual(reportRes.status, 200);
  const report = await reportRes.json();
  assert.strictEqual(report.calls, 1);
  assert.ok(report.prompt_tokens > 0);
  assert.ok(report.completion_tokens > 0);
  assert.ok(report.total_tokens > 0);
  assert.ok(report.cost_nano > 0);
  assert.ok(typeof report.cost_usd === 'string');
  assert.ok(report.by_model[MODEL], 'per-model attribution present');
  console.log('team-a report:', report);

  // 5. No upstream key leak: grep every response/log surface, multi-form
  const key = process.env.FIREWORKS_API_KEY || '';
  const serialized = JSON.stringify({ teamA, teamB, teamAResponseBody, report });
  if (key) {
    assert.ok(!serialized.includes(key), 'FIREWORKS_API_KEY must never appear in gateway output');
  }
});
