### `source/src/app.ts`

```typescript
import { Elysia, t } from 'elysia'
import { openapi } from '@elysiajs/openapi'

// --- L2: custom error class registered via .error() -----------------------
export class NotFoundError extends Error {
  constructor(message = 'Not Found') {
    super(message)
    this.name = 'NotFoundError'
  }
}

export interface User {
  id: number
  name: string
  age: number
}

// --- in-memory store + test isolation helper -------------------------------
let users: User[] = []
let nextId = 1

export function resetDb() {
  users = [
    { id: 1, name: 'Alice', age: 30 },
    { id: 2, name: 'Bob', age: 25 },
  ]
  nextId = 3
}

resetDb()

// --- L1: TypeBox schemas -----------------------------------------------------
const userBody = t.Object({
  name: t.String({ minLength: 1 }),
  age: t.Number({ minimum: 0 }),
})

const idParam = t.Object({
  id: t.Number(),
})

// --- L2: bearer guard --------------------------------------------------------
// IMPORTANT: authorization header MUST be t.Optional(t.String()) — a required
// or t.TemplateLiteral schema fires TypeBox validation (422) before
// beforeHandle ever runs, which breaks the 401-without-token contract.
const AUTH_TOKEN = 'secret-token'

const bearerGuard = {
  headers: t.Object({
    authorization: t.Optional(t.String()),
  }),
  beforeHandle({ headers, error }: any) {
    const auth = headers.authorization
    if (!auth || auth !== `Bearer ${AUTH_TOKEN}`) {
      return error(401, { error: 'unauthorized' })
    }
  },
}

// --- users plugin -------------------------------------------------------------
export const usersPlugin = new Elysia({ prefix: '/users' })
  .get('/', () => users)
  .get(
    '/:id',
    ({ params }) => {
      const user = users.find((u) => u.id === params.id)
      if (!user) throw new NotFoundError('User not found')
      return user
    },
    { params: idParam }
  )
  .guard(bearerGuard, (app) =>
    app
      .post(
        '/',
        ({ body, set }) => {
          const user: User = { id: nextId++, name: body.name, age: body.age }
          users.push(user)
          set.status = 201
          return user
        },
        { body: userBody }
      )
      .put(
        '/:id',
        ({ params, body }) => {
          const idx = users.findIndex((u) => u.id === params.id)
          if (idx === -1) throw new NotFoundError('User not found')
          users[idx] = { id: params.id, name: body.name, age: body.age }
          return users[idx]
        },
        { params: idParam, body: userBody }
      )
      .delete(
        '/:id',
        ({ params, set }) => {
          const idx = users.findIndex((u) => u.id === params.id)
          if (idx === -1) throw new NotFoundError('User not found')
          users.splice(idx, 1)
          set.status = 204
        },
        { params: idParam }
      )
  )

// --- root app -------------------------------------------------------------
export const app = new Elysia()
  .use(openapi()) // exposes GET /openapi/json, 3.0.3 spec
  .error({ NOT_FOUND: NotFoundError })
  .onError(({ code, error, set }) => {
    if (code === 'NOT_FOUND') {
      set.status = 404
      return { error: (error as NotFoundError).message }
    }
    if (code === 'VALIDATION') {
      set.status = 422
      return { error: 'validation failed' }
    }
  })
  .use(usersPlugin)

export type App = typeof app
```

**Fallback if `.guard(options, callback)` doesn't type-check on your installed version**: replace the guard block with the sequential chain form:

```typescript
export const usersPlugin = new Elysia({ prefix: '/users' })
  .get('/', () => users)
  .get('/:id', /* ... */, { params: idParam })
  .guard(bearerGuard)
  .post('/', /* ... */, { body: userBody })
  .put('/:id', /* ... */, { params: idParam, body: userBody })
  .delete('/:id', /* ... */, { params: idParam })
```

Both forms are real Elysia APIs; which one compiles depends on the exact minor version resolved by `bun install`.

