import { describe, expect, it, beforeEach } from 'bun:test'
import { treaty } from '@elysiajs/eden'
import { app, resetDb, type App } from '../src/app'

const api = treaty<App>(app)
const AUTH = 'Bearer secret-token'

beforeEach(() => {
  resetDb()
})

describe('L0 — in-process handle', () => {
  it('GET /users/ returns seeded users', async () => {
    const res = await app.handle(new Request('http://localhost/users/'))
    const body = await res.json()
    expect(res.status).toBe(200)
    expect(body.length).toBe(2)
  })

  it('GET /users/:id 404 on missing', async () => {
    const res = await app.handle(new Request('http://localhost/users/999'))
    expect(res.status).toBe(404)
    const body = await res.json()
    expect(body.error).toBeDefined()
  })
})

describe('L1 — TypeBox validation', () => {
  it('POST /users/ 422 on invalid body', async () => {
    const res = await app.handle(
      new Request('http://localhost/users/', {
        method: 'POST',
        headers: {
          'content-type': 'application/json',
          authorization: AUTH,
        },
        body: JSON.stringify({ name: '', age: -1 }),
      })
    )
    expect(res.status).toBe(422)
  })

  it('param coercion: string "7" in URL resolves to number route', async () => {
    const res = await app.handle(new Request('http://localhost/users/7'))
    // 404 (no user with id 7) proves the string was coerced to a number and
    // matched the /:id route — a non-numeric string would 422/404 differently
    expect(res.status).toBe(404)
  })
})

describe('L2 — auth guard + centralized error handling', () => {
  it('POST /users/ 401 without token', async () => {
    const { status } = await api.users.post({ name: 'Carol', age: 22 })
    expect(status).toBe(401)
  })

  it('POST /users/ 201 with valid token', async () => {
    const { data, status } = await api.users.post(
      { name: 'Carol', age: 22 },
      { headers: { authorization: AUTH } }
    )
    expect(status).toBe(201)
    expect(data?.name).toBe('Carol')
  })
})

describe('L3 — Eden Treaty full CRUD lifecycle', () => {
  it('create → read → update → delete', async () => {
    const created = await api.users.post(
      { name: 'Dave', age: 40 },
      { headers: { authorization: AUTH } }
    )
    expect(created.status).toBe(201)
    const id = created.data!.id

    const read = await api.users({ id }).get()
    expect(read.status).toBe(200)
    expect(read.data?.name).toBe('Dave')

    const updated = await api.users({ id }).put(
      { name: 'Dave Updated', age: 41 },
      { headers: { authorization: AUTH } }
    )
    expect(updated.status).toBe(200)
    expect(updated.data?.name).toBe('Dave Updated')

    // Eden Treaty DELETE convention: first arg is body (undefined for DELETE),
    // second arg is request options.
    const deleted = await (api.users as any)({ id }).delete(undefined, {
      headers: { authorization: AUTH },
    })
    expect(deleted.status).toBe(204)

    const afterDelete = await api.users({ id }).get()
    expect(afterDelete.status).toBe(404)
  })
})

describe('L4 — OpenAPI auto-doc', () => {
  it('GET /openapi/json exposes CRUD paths with trailing-slash prefix', async () => {
    const res = await app.handle(new Request('http://localhost/openapi/json'))
    expect(res.status).toBe(200)
    const spec = await res.json()
    expect(spec.openapi).toBe('3.0.3')
    expect(spec.paths['/users/']).toBeDefined()
    expect(spec.paths['/users/{id}']).toBeDefined()
  })
})
