import React, { useState, useCallback } from 'react';

export default function App() {
  const [prompt, setPrompt] = useState('Reply with exactly: ARIA_CAPSTONE_OK');
  const [answer, setAnswer] = useState('');
  const [mic, setMic] = useState(null);
  const [sources, setSources] = useState([]);
  const [readout, setReadout] = useState(null);
  const [state, setState] = useState(null);

  const askClaude = useCallback(() => {
    setAnswer('');
    window.api.onAiDelta((d) => setAnswer((a) => a + d.text));
    window.api.onAiDone((d) => setAnswer(d.answer));
    window.api.onAiError((e) => setAnswer(`ERROR: ${e.message}`));
    window.api.aiAsk(prompt);
  }, [prompt]);

  const recordMic = useCallback(async () => {
    const result = await window.api.recordMicProbe();
    setMic(result);
  }, []);

  const listSources = useCallback(async () => {
    const s = await window.api.listScreenSources();
    setSources(s);
  }, []);

  const readSystem = useCallback(async () => {
    const r = await window.api.readSystem();
    setReadout(r);
  }, []);

  const bumpStore = useCallback(async () => {
    const s = await window.api.bumpState();
    setState(s);
  }, []);

  return (
    <div style={{ fontFamily: 'system-ui', padding: 16 }}>
      <h2>Aria</h2>

      <section>
        <input value={prompt} onChange={(e) => setPrompt(e.target.value)} style={{ width: 320 }} />
        <button onClick={askClaude}>Ask Claude</button>
        <pre>{answer}</pre>
      </section>

      <section>
        <button onClick={recordMic}>Mic Record</button>
        <pre>{mic && JSON.stringify(mic)}</pre>
      </section>

      <section>
        <button onClick={listSources}>Screen Sources</button>
        <pre>{JSON.stringify(sources)}</pre>
      </section>

      <section>
        <button onClick={readSystem}>System Readout</button>
        <pre>{readout && JSON.stringify(readout)}</pre>
      </section>

      <section>
        <button onClick={bumpStore}>Store State</button>
        <pre>{state && JSON.stringify(state)}</pre>
      </section>
    </div>
  );
}
