### `source/electron/preload.cjs`

```cjs
const { contextBridge, ipcRenderer } = require('electron');

// Exactly 10 whitelisted channels/methods — the security trinity boundary.
contextBridge.exposeInMainWorld('api', {
  aiAsk: (prompt) => ipcRenderer.send('ai:ask', prompt),
  onAiDelta: (cb) => ipcRenderer.on('ai:delta', (_e, data) => cb(data)),
  onAiDone: (cb) => ipcRenderer.on('ai:done', (_e, data) => cb(data)),
  onAiError: (cb) => ipcRenderer.on('ai:error', (_e, data) => cb(data)),
  readSystem: () => ipcRenderer.invoke('system:readout'),

  // Mic capture uses real web APIs available in the preload's isolated renderer context —
  // no main-process round trip is needed for getUserMedia/MediaRecorder.
  recordMicProbe: async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const track = stream.getAudioTracks()[0];
      const trackLabel = track ? track.label : 'unknown';
      return await new Promise((resolve) => {
        const chunks = [];
        const recorder = new MediaRecorder(stream);
        recorder.ondataavailable = (e) => {
          if (e.data && e.data.size > 0) chunks.push(e.data);
        };
        recorder.onstop = () => {
          const recordedBytes = chunks.reduce((sum, b) => sum + b.size, 0);
          const trackState = track.readyState;
          track.stop();
          resolve({ ok: true, trackLabel, trackState, recordedBytes });
        };
        recorder.start();
        setTimeout(() => recorder.stop(), 500);
      });
    } catch (err) {
      return { ok: false, error: String(err) };
    }
  },

  listScreenSources: () => ipcRenderer.invoke('screen:list-sources'),
  requestTouchID: (reason) => ipcRenderer.invoke('touchid:request', reason),
  getState: () => ipcRenderer.invoke('store:get-state'),
  bumpState: () => ipcRenderer.invoke('store:bump-state'),
});
```

**Pitfall:** `desktopCapturer.getSources` and `systemPreferences.canPromptTouchID/promptTouchID` are **main-process-only** APIs on modern Electron (20+) — they are NOT reachable from the renderer even with nodeIntegration on, so they must be proxied via `ipcMain.handle`. `getUserMedia`/`MediaRecorder`, by contrast, are standard web APIs and work directly in the preload's isolated world — no IPC hop needed.

