### `source/electron/main.cjs`

```cjs
const {
  app,
  BrowserWindow,
  ipcMain,
  Tray,
  Menu,
  nativeImage,
  desktopCapturer,
  powerMonitor,
  systemPreferences,
  crashReporter,
} = require('electron');
const path = require('path');
const fs = require('fs');
const https = require('https');

function log(op, level, extra = {}) {
  console.log(JSON.stringify({ ts: new Date().toISOString(), op, level, ...extra }));
}

process.on('unhandledRejection', (reason) => {
  log('process', 'error', { code: 'UNHANDLED_REJECTION', message: String(reason) });
  // process intentionally survives — proof of resilience for L5 evidence
});

crashReporter.start({
  companyName: 'AriaCapstone',
  submitURL: 'https://example.com/crash-report',
  uploadToServer: false,
});

const gotLock = app.requestSingleInstanceLock();
if (!gotLock) {
  app.quit();
}

let mainWindow = null;
let tray = null;

const storePath = path.join(app.getPath('userData'), 'aria-state.json');

function readStore() {
  try {
    return JSON.parse(fs.readFileSync(storePath, 'utf8'));
  } catch {
    return { count: 0 };
  }
}

function writeStore(state) {
  fs.mkdirSync(path.dirname(storePath), { recursive: true });
  fs.writeFileSync(storePath, JSON.stringify(state));
}

function createWindow() {
  mainWindow = new BrowserWindow({
    width: 420,
    height: 640,
    show: false,
    webPreferences: {
      preload: path.join(__dirname, 'preload.cjs'),
      contextIsolation: true,
      sandbox: true,
      nodeIntegration: false,
    },
  });

  mainWindow.loadFile(path.join(__dirname, '..', 'dist', 'index.html'));

  mainWindow.on('close', (e) => {
    if (!app.isQuitting) {
      e.preventDefault();
      mainWindow.hide();
    }
  });
}

function createTray() {
  const icon = nativeImage.createEmpty();
  tray = new Tray(icon);
  tray.setToolTip('Aria');
  tray.setContextMenu(
    Menu.buildFromTemplate([
      { label: 'Show Aria', click: () => mainWindow.show() },
      { type: 'separator' },
      { label: 'Quit', click: () => { app.isQuitting = true; app.quit(); } },
    ]),
  );
  tray.on('click', () => mainWindow.show());
  return tray;
}

app.whenReady().then(() => {
  if (process.platform === 'darwin' && app.dock) app.dock.hide(); // menu-bar app, no dock icon
  createWindow();
  createTray();
  log('app', 'info', { code: 'READY', electron: process.versions.electron });
});

app.on('window-all-closed', () => {
  // Tray app: do not quit when window closes
});

// ---- IPC handlers ----

ipcMain.handle('system:readout', async () => {
  const idleState = powerMonitor.getSystemIdleState(60);
  const onBattery = powerMonitor.isOnBatteryPower();
  const thermalState = powerMonitor.getCurrentThermalState
    ? powerMonitor.getCurrentThermalState()
    : 'unknown';
  const cameraStatus = systemPreferences.getMediaAccessStatus('camera');
  const micStatus = systemPreferences.getMediaAccessStatus('microphone');
  const canPromptTouchID = systemPreferences.canPromptTouchID
    ? systemPreferences.canPromptTouchID()
    : false;
  const effectiveAppearance = systemPreferences.getEffectiveAppearance
    ? systemPreferences.getEffectiveAppearance()
    : 'unknown';
  const accentColor = systemPreferences.getAccentColor
    ? systemPreferences.getAccentColor()
    : '';
  return {
    idleState,
    onBattery,
    thermalState,
    cameraStatus,
    micStatus,
    canPromptTouchID,
    effectiveAppearance,
    accentColor,
  };
});

ipcMain.handle('screen:list-sources', async () => {
  const sources = await desktopCapturer.getSources({ types: ['screen'] });
  return sources.map((s) => ({ id: s.id, name: s.name }));
});

ipcMain.handle('touchid:request', async () => {
  try {
    const can = systemPreferences.canPromptTouchID ? systemPreferences.canPromptTouchID() : false;
    if (!can) return { canPromptTouchID: false, note: 'Touch ID not available on this device' };
    // NOTE: promptTouchID(reason) raises a real biometric GUI dialog and only resolves when a
    // human touches the sensor. It is intentionally NOT invoked here — capability only.
    return {
      canPromptTouchID: true,
      note: 'promptTouchID is GUI-gated — biometric prompt not auto-confirmed',
    };
  } catch (err) {
    return { canPromptTouchID: false, error: String(err) };
  }
});

ipcMain.handle('store:get-state', async () => readStore());

ipcMain.handle('store:bump-state', async () => {
  const state = readStore();
  state.count = (state.count || 0) + 1;
  writeStore(state);
  log('store', 'info', { code: 'STORE_BUMP', count: state.count, path: storePath });
  return state;
});

ipcMain.on('ai:ask', (event, prompt) => {
  const sender = event.sender;
  const apiKey = process.env.ANTHROPIC_API_KEY;

  if (!apiKey) {
    sender.send('ai:error', { message: 'ANTHROPIC_API_KEY missing' });
    log('ai:ask', 'error', { code: 'NO_API_KEY', keyPresent: false });
    return;
  }

  const body = JSON.stringify({
    model: 'claude-haiku-4-5-20251001',
    max_tokens: 256,
    stream: true,
    messages: [{ role: 'user', content: prompt }],
  });

  const req = https.request(
    'https://api.anthropic.com/v1/messages',
    {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        'x-api-key': apiKey,
        'anthropic-version': '2023-06-01',
        'content-length': Buffer.byteLength(body),
      },
    },
    (res) => {
      let buffer = '';
      let msgId = null;
      let deltaEvents = 0;
      let answer = '';

      res.setEncoding('utf8');
      res.on('data', (chunk) => {
        buffer += chunk;
        let idx;
        while ((idx = buffer.indexOf('\n\n')) >= 0) {
          const rawEvent = buffer.slice(0, idx);
          buffer = buffer.slice(idx + 2);
          let data = null;
          for (const line of rawEvent.split('\n')) {
            if (line.startsWith('data:')) data = line.slice(5).trim();
          }
          if (!data) continue;
          try {
            const parsed = JSON.parse(data);
            if (parsed.type === 'message_start') {
              msgId = parsed.message?.id;
            }
            if (parsed.type === 'content_block_delta' && parsed.delta?.text) {
              deltaEvents += 1;
              answer += parsed.delta.text;
              sender.send('ai:delta', { text: parsed.delta.text, msgId });
            }
            if (parsed.type === 'message_stop') {
              sender.send('ai:done', { msgId, deltaEvents, answer });
              log('ai:ask', 'info', { code: 'AI_DONE', msgId, deltaEvents, keyPresent: true });
            }
          } catch {
            // partial JSON chunk — wait for more data
          }
        }
      });
    },
  );

  req.on('error', (err) => {
    sender.send('ai:error', { message: String(err) });
    log('ai:ask', 'error', { code: 'AI_HTTP_ERROR', message: String(err) });
  });

  req.write(body);
  req.end();
});
