```js
import { test, describe, beforeEach } from 'node:test'
import assert from 'node:assert/strict'
import { Hono } from 'hono'
import { secureHeaders } from 'hono/secure-headers'
import { cors } from 'hono/cors'
import { zValidator } from '@hono/zod-validator'
import { z } from 'zod'
import { SignJWT, jwtVerify } from 'jose'

// ---------------------------------------------------------------------------
// JWT helpers — HS256, in-memory secret (test-only, never persisted)
// ---------------------------------------------------------------------------
const JWT_SECRET = new TextEncoder().encode(
  'capstone-test-secret-do-not-use-in-production'
)

async function signToken(payload = { sub: 'test-user' }) {
  return new SignJWT(payload)
    .setProtectedHeader({ alg: 'HS256' })
    .setIssuedAt()
    .setExpirationTime('1h')
    .sign(JWT_SECRET)
}

// ---------------------------------------------------------------------------
// In-memory store — reset per test via beforeEach
// ---------------------------------------------------------------------------
let items = []
let nextId = 1

function resetStore() {
  items = []
  nextId = 1
}

// ---------------------------------------------------------------------------
// Schema (zod@4)
// ---------------------------------------------------------------------------
const itemBody = z.object({
  name: z.string().min(1),
  qty: z.number().int().nonnegative(),
})

// ---------------------------------------------------------------------------
// bearerGuard — must run BEFORE zValidator so auth rejection fires before
// body parsing (guards gate; validators don't).
// ---------------------------------------------------------------------------
const bearerGuard = async (c, next) => {
  const authHeader = c.req.header('Authorization')
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return c.json({ error: 'unauthorized' }, 401)
  }
  const token = authHeader.slice('Bearer '.length)
  try {
    await jwtVerify(token, JWT_SECRET)
  } catch {
    return c.json({ error: 'unauthorized' }, 401)
  }
  await next()
}

// ---------------------------------------------------------------------------
// App
// ---------------------------------------------------------------------------
function buildApp() {
  const app = new Hono()

  app.use('*', secureHeaders())
  app.use(
    '*',
    cors({
      origin: 'https://example.com',
      allowMethods: ['GET', 'POST', 'PUT', 'DELETE'],
    })
  )

  const jsonValidator = zValidator('json', itemBody, (result, c) => {
    if (!result.success) {
      return c.json(
        {
          success: false,
          error: {
            name: result.error.name,
            message: result.error.message,
          },
        },
        400
      )
    }
  })

  app.get('/items', (c) => c.json(items))

  app.get('/items/:id', (c) => {
    const id = Number(c.req.param('id'))
    const item = items.find((i) => i.id === id)
    if (!item) return c.json({ error: 'not found' }, 404)
    return c.json(item)
  })

  app.post('/items', bearerGuard, jsonValidator, (c) => {
    const body = c.req.valid('json')
    const item = { id: nextId++, ...body }
    items.push(item)
    return c.json(item, 201)
  })

  app.put('/items/:id', bearerGuard, jsonValidator, (c) => {
    const id = Number(c.req.param('id'))
    const idx = items.findIndex((i) => i.id === id)
    if (idx === -1) return c.json({ error: 'not found' }, 404)
    const body = c.req.valid('json')
    items[idx] = { id, ...body }
    return c.json(items[idx], 200)
  })

  // FIXED (was the RED bug): bearerGuard now applied to DELETE.
  app.delete('/items/:id', bearerGuard, (c) => {
    const id = Number(c.req.param('id'))
    const idx = items.findIndex((i) => i.id === id)
    if (idx === -1) return c.json({ error: 'not found' }, 404)
    items.splice(idx, 1)
    return new Response(null, { status: 204 })
  })

  return app
}

const app = buildApp()

// ---------------------------------------------------------------------------
// Tests — all driven through app.request(); no port, no socket.
// ---------------------------------------------------------------------------
describe('L-capstone — CRUD lifecycle + middleware guards', () => {
  beforeEach(() => {
    resetStore()
  })

  test('secureHeaders: X-Frame-Options is set on GET /items', async () => {
    const res = await app.request('/items')
    assert.equal(res.status, 200)
    assert.equal(res.headers.get('X-Frame-Options'), 'SAMEORIGIN')
  })

  test('CORS: Access-Control-Allow-Origin echoes configured origin', async () => {
    const res = await app.request('/items', {
      headers: { Origin: 'https://example.com' },
    })
    assert.equal(
      res.headers.get('Access-Control-Allow-Origin'),
      'https://example.com'
    )
  })

  test('POST /items without Bearer → 401', async () => {
    const res = await app.request('/items', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ name: 'widget', qty: 1 }),
    })
    assert.equal(res.status, 401)
    const body = await res.json()
    assert.deepEqual(body, { error: 'unauthorized' })
  })

  test('PUT /items/:id without Bearer → 401', async () => {
    const res = await app.request('/items/1', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ name: 'widget', qty: 1 }),
    })
    assert.equal(res.status, 401)
  })

  test('DELETE /items/:id without Bearer → 401 (the fixed bug)', async () => {
    const res = await app.request('/items/1', { method: 'DELETE' })
    assert.equal(res.status, 401)
  })

  test('POST /items with invalid body (empty name, negative qty) → 400', async () => {
    const token = await signToken()
    const res = await app.request('/items', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify({ name: '', qty: -5 }),
    })
    assert.equal(res.status, 400)
    const body = await res.json()
    assert.equal(body.success, false)
    assert.equal(body.error.name, 'ZodError')
  })

  test('Full CRUD lifecycle: create → read → list → update → delete → 404', async () => {
    const token = await signToken()
    const authHeaders = {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${token}`,
    }

    // POST -> 201
    const createRes = await app.request('/items', {
      method: 'POST',
      headers: authHeaders,
      body: JSON.stringify({ name: 'widget', qty: 3 }),
    })
    assert.equal(createRes.status, 201)
    const created = await createRes.json()
    assert.equal(created.name, 'widget')
    assert.equal(created.qty, 3)
    assert.ok(created.id)

    // GET /items/1 -> 200
    const getRes = await app.request(`/items/${created.id}`)
    assert.equal(getRes.status, 200)
    const fetched = await getRes.json()
    assert.deepEqual(fetched, created)

    // GET /items -> list length 1
    const listRes = await app.request('/items')
    const list = await listRes.json()
    assert.equal(list.length, 1)

    // PUT -> 200
    const putRes = await app.request(`/items/${created.id}`, {
      method: 'PUT',
      headers: authHeaders,
      body: JSON.stringify({ name: 'widget-updated', qty: 10 }),
    })
    assert.equal(putRes.status, 200)
    const updated = await putRes.json()
    assert.equal(updated.name, 'widget-updated')
    assert.equal(updated.qty, 10)

    // DELETE -> 204
    const deleteRes = await app.request(`/items/${created.id}`, {
      method: 'DELETE',
      headers: { Authorization: `Bearer ${token}` },
    })
    assert.equal(deleteRes.status, 204)
    assert.equal(await deleteRes.text(), '')

    // GET /items/1 -> 404 regression
    const missingRes = await app.request(`/items/${created.id}`)
    assert.equal(missingRes.status, 404)

    // GET /items -> list empty
    const emptyListRes = await app.request('/items')
    const emptyList = await emptyListRes.json()
    assert.deepEqual(emptyList, [])
  })

  test('GET /items/9999 (nonexistent) → 404 not found', async () => {
    const res = await app.request('/items/9999')
    assert.equal(res.status, 404)
  })
})
