import * as React from "react";

type MarkerVariant = "separator" | "default";

interface MarkerProps extends React.HTMLAttributes<HTMLDivElement> {
  variant?: MarkerVariant;
}

// data-variant lands directly on the element returned by the render function
// (mirrors the real shadcn Marker's useRender({ state }) pattern) — this is
// why `data-testid="day-marker"` and `data-variant="separator"` are on the
// SAME node, not a wrapper.
export function Marker({ variant = "default", className, children, ...props }: MarkerProps) {
  return (
    <div data-slot="marker" data-variant={variant} className={className} {...props}>
      {children}
    </div>
  );
}

export function MarkerContent({ className, children, ...props }: React.HTMLAttributes<HTMLDivElement>) {
  return (
    <div data-slot="marker-content" className={className} {...props}>
      {children}
    </div>
  );
}
