```tsx
import * as React from "react";

interface ScrollerContextValue {
  registerItem: (id: string, el: HTMLElement | null) => void;
  scrollToMessage: (id: string) => void;
}

const ScrollerContext = React.createContext<ScrollerContextValue | null>(null);

export function useMessageScroller(): ScrollerContextValue {
  const ctx = React.useContext(ScrollerContext);
  if (!ctx) throw new Error("useMessageScroller must be used within <MessageScrollerProvider>");
  return ctx;
}

interface InternalState {
  viewportEl: HTMLDivElement | null;
  items: Map<string, HTMLElement>;
  autoScroll: boolean;
}

const InternalRefContext = React.createContext<React.MutableRefObject<InternalState> | null>(null);

interface ProviderProps {
  autoScroll?: boolean;
  children: React.ReactNode;
}

export function MessageScrollerProvider({ autoScroll = false, children }: ProviderProps) {
  const internalRef = React.useRef<InternalState>({
    viewportEl: null,
    items: new Map(),
    autoScroll,
  });
  internalRef.current.autoScroll = autoScroll;

  const registerItem = React.useCallback((id: string, el: HTMLElement | null) => {
    if (el) internalRef.current.items.set(id, el);
    else internalRef.current.items.delete(id);
  }, []);

  const scrollToMessage = React.useCallback((id: string) => {
    internalRef.current.items.get(id)?.scrollIntoView({ block: "center", behavior: "auto" });
  }, []);

  const value = React.useMemo(() => ({ registerItem, scrollToMessage }), [registerItem, scrollToMessage]);

  return (
    <InternalRefContext.Provider value={internalRef}>
      <ScrollerContext.Provider value={value}>{children}</ScrollerContext.Provider>
    </InternalRefContext.Provider>
  );
}

export function MessageScroller({ className, children, ...props }: React.HTMLAttributes<HTMLDivElement>) {
  return (
    <div data-slot="message-scroller" className={className} {...props}>
      {children}
    </div>
  );
}

export function MessageScrollerViewport({ className, children, ...props }: React.HTMLAttributes<HTMLDivElement>) {
  const internalRef = React.useContext(InternalRefContext);

  const setViewport = React.useCallback(
    (el: HTMLDivElement | null) => {
      if (internalRef) internalRef.current.viewportEl = el;
    },
    [internalRef]
  );

  return (
    <div
      data-slot="message-scroller-viewport"
      data-testid="message-scroller-viewport"
      ref={setViewport}
      className={className}
      style={{ overflowY: "auto" }}
      {...props}
    >
      {children}
    </div>
  );
}

// autoScroll is a PROVIDER behavior: it watches for new children being
// appended to the content node and, if enabled, scrolls the viewport to the
// bottom. No component calls this manually — it fires from the MutationObserver.
export function MessageScrollerContent({ className, children, ...props }: React.HTMLAttributes<HTMLDivElement>) {
  const internalRef = React.useContext(InternalRefContext);
  const contentRef = React.useRef<HTMLDivElement | null>(null);

  React.useEffect(() => {
    const el = contentRef.current;
    if (!el || !internalRef) return;

    const observer = new MutationObserver(() => {
      if (!internalRef.current.autoScroll) return;
      const viewport = internalRef.current.viewportEl;
      if (viewport) viewport.scrollTop = viewport.scrollHeight;
    });
    observer.observe(el, { childList: true });
    return () => observer.disconnect();
  }, [internalRef]);

  return (
    <div data-slot="message-scroller-content" ref={contentRef} className={className} {...props}>
      {children}
    </div>
  );
}

export function MessageScrollerItem({
  messageId,
  className,
  children,
  ...props
}: React.HTMLAttributes<HTMLDivElement> & { messageId: string }) {
  const ctx = React.useContext(ScrollerContext);

  const setRef = React.useCallback(
    (el: HTMLDivElement | null) => ctx?.registerItem(messageId, el),
    [ctx, messageId]
  );

  return (
    <div
      data-slot="message-scroller-item"
      data-message-id={messageId}
      ref={setRef}
      className={className}
      {...props}
    >
      {children}
    </div>
  );
}
