## `src/harness/chat.tsx` — the harness component

```tsx
import * as React from "react";
import { Marker, MarkerContent } from "../components/ui/marker";
import { Message, MessageGroup, MessageContent } from "../components/ui/message";
import { Bubble, BubbleContent } from "../components/ui/bubble";
import { Attachment, AttachmentTitle } from "../components/ui/attachment";
import {
  MessageScrollerProvider,
  MessageScroller,
  MessageScrollerViewport,
  MessageScrollerContent,
  MessageScrollerItem,
  useMessageScroller,
} from "../components/ui/message-scroller";

// NOTE (G-WORKFLOW): no Date.now(), no new Date(), no Math.random() anywhere
// in this file. IDs are a deterministic counter; the streaming delay uses
// window.setTimeout only.

type Role = "user" | "assistant";

interface ChatMessage {
  id: string;
  role: Role;
  align: "start" | "end";
  variant: "default" | "secondary";
  text: string;
  streaming?: boolean;
}

function buildSeedMessages(): ChatMessage[] {
  const seedTexts = [
    "Hi! How can I help you today?",
    "Can you explain how MessageScroller works?",
    "Sure — it wraps your message list and auto-scrolls on append.",
    "Does it support jumping to an earlier message?",
    "Yes, via useMessageScroller().scrollToMessage(id).",
    "What about attachments?",
    "Attachments carry a data-state that drives the shimmer indicator.",
    "Neat. What variants does Bubble support?",
    "default and secondary, mapped to assistant/user alignment.",
    "Got it, thanks!",
    "Anytime. Anything else before we wrap up?",
    "Not yet, let me try streaming a reply.",
  ];

  return seedTexts.map((text, i) => {
    const role: Role = i % 2 === 0 ? "assistant" : "user";
    return {
      id: `msg-${i}`,
      role,
      align: role === "assistant" ? "start" : "end",
      variant: role === "assistant" ? "default" : "secondary",
      text,
    };
  });
}

function Controls({
  onSend,
}: {
  onSend: (text: string) => void;
}) {
  const [value, setValue] = React.useState("");
  const { scrollToMessage } = useMessageScroller();

  return (
    <div data-slot="chat-controls">
      <input
        data-testid="chat-input"
        value={value}
        onChange={(e) => setValue(e.target.value)}
      />
      <button
        data-testid="send-button"
        onClick={() => {
          if (!value.trim()) return;
          onSend(value);
          setValue("");
        }}
      >
        send
      </button>
      <button data-testid="jump-first-button" onClick={() => scrollToMessage("msg-0")}>
        jump first
      </button>
    </div>
  );
}

export function ChatHarness() {
  const [messages, setMessages] = React.useState<ChatMessage[]>(buildSeedMessages);
  const [attachmentState, setAttachmentState] = React.useState<"uploading" | "done">("uploading");
  const nextId = React.useRef(buildSeedMessages().length); // starts at 12

  const handleSend = React.useCallback((text: string) => {
    const userId = `msg-${nextId.current++}`;
    const assistantId = `msg-${nextId.current++}`;

    setMessages((prev) => [
      ...prev,
      { id: userId, role: "user", align: "end", variant: "secondary", text },
      { id: assistantId, role: "assistant", align: "start", variant: "default", text: "", streaming: true },
    ]);

    window.setTimeout(() => {
      setMessages((prev) =>
        prev.map((m) =>
          m.id === assistantId ? { ...m, streaming: false, text: "Sure, here is the answer." } : m
        )
      );
    }, 600);
  }, []);

  return (
    <div data-slot="chat-harness">
      <section data-slot="attachment-demo-section">
        <Attachment data-testid="attachment-demo" state={attachmentState}>
          <AttachmentTitle>design-spec.pdf</AttachmentTitle>
          <button
            data-testid="finish-upload"
            onClick={() => setAttachmentState("done")}
          >
            finish upload
          </button>
        </Attachment>
      </section>

      <MessageScrollerProvider autoScroll>
        <MessageScroller>
          <MessageScrollerViewport>
            <MessageScrollerContent>
              <Marker variant="separator" data-testid="day-marker">
                <MarkerContent>Today</MarkerContent>
              </Marker>

              {messages.map((m) => (
                <MessageScrollerItem key={m.id} messageId={m.id}>
                  <MessageGroup>
                    <Message align={m.align}>
                      <MessageContent>
                        <Bubble variant={m.variant}>
                          <BubbleContent>
                            {m.streaming ? (
                              <span data-testid="thinking" className="shimmer">
                                Thinking…
                              </span>
                            ) : (
                              <span data-testid={`text-${m.id}`}>{m.text}</span>
                            )}
                          </BubbleContent>
                        </Bubble>
                      </MessageContent>
                    </Message>
                  </MessageGroup>
                </MessageScrollerItem>
              ))}
            </MessageScrollerContent>
          </MessageScrollerViewport>
        </MessageScroller>

        <Controls onSend={handleSend} />
      </MessageScrollerProvider>
    </div>
  );
}
```

Because the seed array has 12 entries (`msg-0` … `msg-11`), a single `send`
produces `msg-12` (user) and `msg-13` (assistant) — matching the RED/GREEN
evidence's `data-testid="text-msg-13"`.

