## `source/pipeline.js`

```js
'use strict';
const { Client } = require('pg');

const CONN = {
  host: '127.0.0.1',
  port: 54322,
  user: 'postgres',
  password: 'postgres',
  database: 'postgres',
};

const QUEUE = 'au_d07_cap_work';
const TABLE = 'public.au_d07_cap_documents';
const CRON_JOB = 'au_d07_cap_worker';

async function connect() {
  const client = new Client(CONN);
  await client.connect();
  return client;
}

async function setup(client) {
  await client.query(`create extension if not exists pgcrypto;`);

  await client.query(`
    create table if not exists ${TABLE} (
      id uuid primary key default gen_random_uuid(),
      content text not null,
      status text not null default 'pending',
      result jsonb,
      processed_at timestamptz
    );
  `);

  // pgmq.create is safe to call repeatedly; guard anyway for older versions
  // that raise "already exists" instead of being idempotent.
  await client.query(`select pgmq.create('${QUEUE}');`).catch((e) => {
    if (!/already exists/i.test(e.message)) throw e;
  });

  await client.query(`
    create or replace function public.au_d07_cap_enqueue_fn() returns trigger
    language plpgsql as $fn$
    begin
      perform pgmq.send('${QUEUE}', jsonb_build_object('id', NEW.id));
      return NEW;
    end;
    $fn$;
  `);

  await client.query(`drop trigger if exists au_d07_cap_enqueue on ${TABLE};`);
  await client.query(`
    create trigger au_d07_cap_enqueue
      after insert on ${TABLE}
      for each row execute function public.au_d07_cap_enqueue_fn();
  `);

  await client.query(`
    create or replace function public.au_d07_cap_process() returns void
    language plpgsql as $fn$
    declare
      msg record;
      doc record;
      computed_hash text;
      char_len int;
    begin
      for msg in select * from pgmq.read('${QUEUE}', 30, 10)
      loop
        begin
          select * into doc from ${TABLE} where id = (msg.message->>'id')::uuid;
          if not found then
            raise exception 'document % not found', msg.message->>'id';
          end if;

          -- deterministic error-injection hook, exercised by R2
          if doc.content = '__FORCE_ERROR__' then
            raise exception 'forced test error for %', doc.id;
          end if;

          char_len := length(doc.content);
          computed_hash := encode(digest(doc.content, 'sha256'), 'hex');

          update ${TABLE}
            set status = 'done',
                result = jsonb_build_object('char_count', char_len, 'sha256', computed_hash),
                processed_at = now()
            where id = doc.id;

          -- delete ONLY on success
          perform pgmq.delete('${QUEUE}', msg.msg_id);
        exception when others then
          update ${TABLE}
            set status = 'error',
                result = jsonb_build_object('error', SQLERRM),
                processed_at = now()
            where id = (msg.message->>'id')::uuid;
          -- message intentionally left in the queue (not deleted) so a
          -- transient failure remains retryable after vt expires
        end;
      end loop;
    end;
    $fn$;
  `);
}

async function scheduleCron(client) {
  await client.query(
    `select cron.schedule('${CRON_JOB}', '5 seconds', $$select public.au_d07_cap_process()$$);`
  );
}

async function unscheduleCron(client) {
  await client.query(`select cron.unschedule('${CRON_JOB}');`).catch(() => {});
}

async function teardown(client) {
  await unscheduleCron(client);
  await client.query(`drop trigger if exists au_d07_cap_enqueue on ${TABLE};`);
  await client.query(`drop function if exists public.au_d07_cap_enqueue_fn();`);
  await client.query(`drop function if exists public.au_d07_cap_process();`);
  await client.query(`select pgmq.drop_queue('${QUEUE}');`).catch(() => {});
  await client.query(`drop table if exists ${TABLE};`);
}

async function insertDocs(client, contents) {
  const ids = [];
  for (const content of contents) {
    const res = await client.query(
      `insert into ${TABLE} (content) values ($1) returning id`,
      [content]
    );
    ids.push(res.rows[0].id);
  }
  return ids;
}

async function getQueueLength(client) {
  const res = await client.query(`select queue_length from pgmq.metrics('${QUEUE}');`);
  return Number(res.rows[0].queue_length);
}

async function getDocs(client, ids) {
  const res = await client.query(
    `select id, content, status, result, processed_at from ${TABLE} where id = any($1::uuid[])`,
    [ids]
  );
  return res.rows;
}

async function pollUntil(fn, { timeoutMs = 20000, intervalMs = 500 } = {}) {
  const start = Date.now();
  while (Date.now() - start < timeoutMs) {
    const result = await fn();
    if (result) return result;
    await new Promise((r) => setTimeout(r, intervalMs));
  }
  throw new Error(`pollUntil: condition not met within ${timeoutMs}ms`);
}

module.exports = {
  CONN, QUEUE, TABLE, CRON_JOB,
  connect, setup, teardown, scheduleCron, unscheduleCron,
  insertDocs, getQueueLength, getDocs, pollUntil,
};
```

