'use strict';
const test = require('node:test');
const assert = require('node:assert/strict');
const pipeline = require('./pipeline');

let client;

test.before(async () => {
  client = await pipeline.connect();
  await pipeline.setup(client);
  // NOTE: cron is deliberately NOT scheduled in the red suite.
});

test.after(async () => {
  const cleanup = await pipeline.connect();
  await pipeline.teardown(cleanup); // fresh connection: survives a dead socket
  await cleanup.end();
  await client.end();
});

test('RED: trigger enqueues synchronously, but with no worker running docs stay pending', async () => {
  const ids = await pipeline.insertDocs(client, [
    'red doc one',
    'red doc two',
    'red doc three',
  ]);

  // Proves the AFTER INSERT trigger fires synchronously inside the INSERT.
  const queueLength = await pipeline.getQueueLength(client);
  assert.equal(queueLength, 3, 'trigger must enqueue all 3 rows before any worker runs');

  // Genuine failing assertion: no cron job has run, so nothing is 'done' yet.
  const docs = await pipeline.getDocs(client, ids);
  const allDone = docs.every((d) => d.status === 'done');
  assert.equal(
    allDone,
    true,
    'EXPECTED FAILURE: docs are still status=pending because no worker has processed the queue'
  );
});
