## `source/green.test.js`

```js
'use strict';
const test = require('node:test');
const assert = require('node:assert/strict');
const crypto = require('node:crypto');
const pipeline = require('./pipeline');

let client;

test.before(async () => {
  client = await pipeline.connect();
  await pipeline.setup(client);
  await pipeline.scheduleCron(client);
});

test.after(async () => {
  const cleanup = await pipeline.connect();
  await pipeline.teardown(cleanup);
  await cleanup.end();
  await client.end();
});

test('GREEN: worker drains the queue; docs end done with cross-checked sha256', async () => {
  const contents = ['hello world', 'async job pipeline', 'pgmq + pg_cron'];
  const ids = await pipeline.insertDocs(client, contents);

  const queueLength = await pipeline.getQueueLength(client);
  assert.equal(queueLength, 3);

  const docs = await pipeline.pollUntil(async () => {
    const rows = await pipeline.getDocs(client, ids);
    return rows.every((r) => r.status === 'done') ? rows : null;
  });

  for (const row of docs) {
    const idx = ids.indexOf(row.id);
    const expectedHash = crypto.createHash('sha256').update(contents[idx]).digest('hex');
    assert.equal(row.result.sha256, expectedHash, 'DB sha256 must match independent Node digest');
    assert.equal(row.result.char_count, contents[idx].length);
    assert.ok(row.processed_at);
  }
});

test('R1: a doc inserted after the pipeline is already running is also processed', async () => {
  const [id] = await pipeline.insertDocs(client, ['post-pipeline doc']);
  const [row] = await pipeline.pollUntil(async () => {
    const rows = await pipeline.getDocs(client, [id]);
    return rows[0].status === 'done' ? rows : null;
  });
  assert.equal(row.status, 'done');
});

test('R2: an erroring doc is isolated as status=error; good rows in the same batch still complete', async () => {
  const ids = await pipeline.insertDocs(client, [
    'good doc a',
    '__FORCE_ERROR__',
    'good doc b',
  ]);

  const rows = await pipeline.pollUntil(async () => {
    const current = await pipeline.getDocs(client, ids);
    return current.every((r) => r.status === 'done' || r.status === 'error') ? current : null;
  });

  const byContent = Object.fromEntries(rows.map((r) => [r.content, r]));
  assert.equal(byContent['good doc a'].status, 'done');
  assert.equal(byContent['good doc b'].status, 'done');
  assert.equal(byContent['__FORCE_ERROR__'].status, 'error');
  assert.match(byContent['__FORCE_ERROR__'].result.error, /forced test error/);
});

test('cron.job_run_details shows the worker actually fired on its own schedule', async () => {
  const res = await pipeline.pollUntil(async () => {
    const r = await client.query(
      `select jrd.status
         from cron.job_run_details jrd
         join cron.job j on j.jobid = jrd.jobid
        where j.jobname = $1 and jrd.status = 'succeeded'
        order by jrd.end_time desc
        limit 1`,
      [pipeline.CRON_JOB]
    );
    return r.rows.length ? r.rows : null;
  }, { timeoutMs: 15000, intervalMs: 1000 });
  assert.equal(res[0].status, 'succeeded');
});
```

