## `source/src/db.ts` — L7 (`bun:sqlite`)

```ts
import { Database } from "bun:sqlite";
import { mkdirSync } from "node:fs";
import { dirname } from "node:path";

export interface UserRow {
  id: number;
  username: string;
  password_hash: string;
  created_at: string;
}

export interface LinkRow {
  id: number;
  slug: string;
  url: string;
  user_id: number;
  created_at: string;
}

export interface TaskRow {
  id: number;
  title: string;
  done: number; // sqlite has no native boolean
  user_id: number;
  created_at: string;
}

export function createDb(path: string = ":memory:"): Database {
  if (path !== ":memory:") {
    mkdirSync(dirname(path), { recursive: true });
  }

  const db = new Database(path, { create: true });

  // WAL only makes sense for file-backed dbs; skip for :memory:
  if (path !== ":memory:") {
    db.exec("PRAGMA journal_mode = WAL;");
  }

  db.run(`
    CREATE TABLE IF NOT EXISTS users (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      username TEXT UNIQUE NOT NULL,
      password_hash TEXT NOT NULL,
      created_at TEXT NOT NULL DEFAULT (datetime('now'))
    );
  `);

  db.run(`
    CREATE TABLE IF NOT EXISTS links (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      slug TEXT UNIQUE NOT NULL,
      url TEXT NOT NULL,
      user_id INTEGER NOT NULL REFERENCES users(id),
      created_at TEXT NOT NULL DEFAULT (datetime('now'))
    );
  `);

  db.run(`
    CREATE TABLE IF NOT EXISTS tasks (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      title TEXT NOT NULL,
      done INTEGER NOT NULL DEFAULT 0,
      user_id INTEGER NOT NULL REFERENCES users(id),
      created_at TEXT NOT NULL DEFAULT (datetime('now'))
    );
  `);

  return db;
}
```

**Gotcha**: `bun:sqlite`'s bundled SQLite is recent enough to support `INSERT ... RETURNING` (needs ≥3.35); no extra config needed, unlike `node:sqlite`/`better-sqlite3` on older distros.

