## `source/src/server.ts` — L5, L10, L13, L18, L20

```ts
import { createDb, type UserRow, type LinkRow, type TaskRow } from "./db";
import type { Server, ServerWebSocket } from "bun";

export interface WSData {
  topics: string[];
}

// Module-level singleton DB: all links/tasks share one sqlite instance,
// per the capstone concept. NOTE: this means every createServer() call in
// the same process shares this db — fine for a single running app, but
// something to be aware of if you spin up multiple servers in one test file.
const db = createDb(process.env.LINKTRACK_DB ?? ":memory:");

// Simple in-memory session store: token -> userId
const tokens = new Map<string, number>();

// SSE fan-out (separate from the WS pub/sub topic)
type SSEListener = (event: string, data: unknown) => void;
const sseListeners = new Set<SSEListener>();
function broadcastSSE(event: string, data: unknown) {
  for (const listener of sseListeners) listener(event, data);
}

function log(route: string, extra: Record<string, unknown> = {}) {
  // Structured JSON logging on every mutation, per L20. Deliberately on
  // stderr (console.error) — matches the spec's "structured JSON console.error"
  // convention so mutation logs are separable from stdout access logs.
  console.error(JSON.stringify({ level: "info", ts: new Date().toISOString(), route, ...extra }));
}

function jsonResponse(body: unknown, init: ResponseInit = {}): Response {
  return new Response(JSON.stringify(body), {
    ...init,
    headers: { "content-type": "application/json", ...(init.headers ?? {}) },
  });
}

function requireAuth(req: Request): number | null {
  const auth = req.headers.get("authorization");
  if (!auth?.startsWith("Bearer ")) return null;
  return tokens.get(auth.slice("Bearer ".length)) ?? null;
}

function randomSlug(len = 6): string {
  return crypto.randomUUID().replace(/-/g, "").slice(0, len);
}

export function createServer(port: number = 0) {
  const server = Bun.serve<WSData>({
    port,

    routes: {
      "/api/ping": {
        GET: () => jsonResponse({ pong: true, time: Date.now() }),
      },

      "/api/register": {
        POST: async (req) => {
          const { username, password } = await req.json();
          if (!username || !password) {
            return jsonResponse({ error: "username and password required" }, { status: 400 });
          }
          // L10: bcrypt with cost 4 — deliberately weak/fast for test speed.
          const password_hash = await Bun.password.hash(password, {
            algorithm: "bcrypt",
            cost: 4,
          });
          try {
            const row = db
              .query<UserRow, [string, string]>(
                "INSERT INTO users (username, password_hash) VALUES (?, ?) RETURNING *"
              )
              .get(username, password_hash);
            log("/api/register", { username, userId: row?.id });
            return jsonResponse({ id: row?.id, username: row?.username }, { status: 201 });
          } catch (err) {
            log("/api/register", { username, error: String(err) });
            return jsonResponse({ error: "username taken" }, { status: 409 });
          }
        },
      },

      "/api/login": {
        POST: async (req) => {
          const { username, password } = await req.json();
          const row = db
            .query<UserRow, [string]>("SELECT * FROM users WHERE username = ?")
            .get(username);
          if (!row || !(await Bun.password.verify(password, row.password_hash))) {
            log("/api/login", { username, ok: false });
            return jsonResponse({ error: "invalid credentials" }, { status: 401 });
          }
          const token = crypto.randomUUID();
          tokens.set(token, row.id);
          log("/api/login", { username, ok: true, userId: row.id });
          return jsonResponse({ token, userId: row.id });
        },
      },

      "/api/links": {
        GET: (req) => {
          const userId = requireAuth(req);
          if (!userId) return jsonResponse({ error: "unauthorized" }, { status: 401 });
          const rows = db
            .query<LinkRow, [number]>("SELECT * FROM links WHERE user_id = ? ORDER BY id DESC")
            .all(userId);
          return jsonResponse(rows);
        },
        POST: async (req) => {
          const userId = requireAuth(req);
          if (!userId) return jsonResponse({ error: "unauthorized" }, { status: 401 });
          const body = await req.json();
          const url = body.url as string;
          if (!url) return jsonResponse({ error: "url required" }, { status: 400 });
          const slug = (body.slug as string) || randomSlug();
          try {
            const row = db
              .query<LinkRow, [string, string, number]>(
                "INSERT INTO links (slug, url, user_id) VALUES (?, ?, ?) RETURNING *"
              )
              .get(slug, url, userId);
            log("/api/links", { userId, slug, url });

            const event = { type: "link.created", slug: row?.slug, url: row?.url, id: row?.id };
            server.publish("links", JSON.stringify(event)); // L13: WS fan-out
            broadcastSSE("link.created", event); // L18: SSE fan-out

            return jsonResponse(row, { status: 201 });
          } catch (err) {
            log("/api/links", { userId, slug, error: String(err) });
            return jsonResponse({ error: "slug taken" }, { status: 409 });
          }
        },
      },

      "/api/links/:slug": {
        GET: (req: any) => {
          const slug = req.params.slug as string;
          const row = db.query<LinkRow, [string]>("SELECT * FROM links WHERE slug = ?").get(slug);
          if (!row) return jsonResponse({ error: "not found" }, { status: 404 });
          const url = new URL(req.url);
          if (url.searchParams.get("json") === "1") return jsonResponse(row);
          return new Response(null, { status: 302, headers: { Location: row.url } });
        },
      },

      "/api/tasks": {
        GET: (req) => {
          const userId = requireAuth(req);
          if (!userId) return jsonResponse({ error: "unauthorized" }, { status: 401 });
          const rows = db
            .query<TaskRow, [number]>("SELECT * FROM tasks WHERE user_id = ? ORDER BY id DESC")
            .all(userId);
          return jsonResponse(rows);
        },
        POST: async (req) => {
          const userId = requireAuth(req);
          if (!userId) return jsonResponse({ error: "unauthorized" }, { status: 401 });
          const { title } = await req.json();
          if (!title) return jsonResponse({ error: "title required" }, { status: 400 });
          const row = db
            .query<TaskRow, [string, number]>(
              "INSERT INTO tasks (title, user_id) VALUES (?, ?) RETURNING *"
            )
            .get(title, userId);
          log("/api/tasks", { userId, taskId: row?.id, title });
          broadcastSSE("task.created", row);
          return jsonResponse(row, { status: 201 });
        },
      },

      "/events": {
        GET: () => {
          // L18: SSE via ReadableStream — no library, just the raw Response.
          let listener!: SSEListener;
          const stream = new ReadableStream({
            start(controller) {
              controller.enqueue(`event: ping\ndata: connected\n\n`);
              listener = (event, data) => {
                controller.enqueue(`event: ${event}\ndata: ${JSON.stringify(data)}\n\n`);
              };
              sseListeners.add(listener);
            },
            cancel() {
              sseListeners.delete(listener);
            },
          });
          return new Response(stream, {
            headers: {
              "Content-Type": "text/event-stream",
              "Cache-Control": "no-cache",
              Connection: "keep-alive",
            },
          });
        },
      },
    },

    // Fallback fetch handles the WS upgrade (routes object has no upgrade hook)
    fetch(req, server) {
      const url = new URL(req.url);
      if (url.pathname === "/ws") {
        const ok = server.upgrade(req, { data: { topics: ["links"] } });
        if (ok) return undefined; // Bun takes over the socket
        return new Response("upgrade failed", { status: 400 });
      }
      return new Response("not found", { status: 404 });
    },

    websocket: {
      open(ws: ServerWebSocket<WSData>) {
        for (const topic of ws.data.topics) ws.subscribe(topic); // L13
      },
      message() {
        /* no client->server protocol needed for this capstone */
      },
      close(ws: ServerWebSocket<WSData>) {
        for (const topic of ws.data.topics) ws.unsubscribe(topic);
      },
    },
  });

  return server;
}

if (import.meta.main) {
  const port = Number(process.env.PORT ?? 3000);
  const server = createServer(port);
  console.log(`linktrack listening on ${server.url}`);
}
```

**Gotchas worth flagging**:
- `server.publish` only reaches subscribers who called `ws.subscribe(topic)` in `open` — if you publish before any client has subscribed, the message is silently dropped (no queueing). Tests must open the WS and await its `open` event *before* POSTing.
- Bun's `routes` object doesn't get an `upgrade` hook; the WS upgrade must happen in the top-level `fetch` fallback, which only fires for paths *not* matched by `routes`.

