## `source/src/seed.ts` — L12 (`bun build --compile`)

```ts
#!/usr/bin/env bun
import { createDb } from "./db";

const dbPath = process.argv[2] ?? ":memory:";
const db = createDb(dbPath);

const demoUsers = [
  { username: "alice", password: "correct horse battery staple" },
  { username: "bob", password: "hunter2-but-better" },
];

for (const u of demoUsers) {
  const exists = db.query("SELECT id FROM users WHERE username = ?").get(u.username);
  if (exists) {
    console.log(`user ${u.username} already seeded, skipping`);
    continue;
  }
  const password_hash = await Bun.password.hash(u.password, { algorithm: "bcrypt", cost: 4 });
  const row = db
    .query("INSERT INTO users (username, password_hash) VALUES (?, ?) RETURNING id, username")
    .get(u.username, password_hash);
  console.log("seeded user", row);
}

const alice = db.query("SELECT id FROM users WHERE username = 'alice'").get() as { id: number };

const demoLinks = [
  { slug: "bun-docs", url: "https://bun.sh/docs" },
  { slug: "bun-sqlite", url: "https://bun.sh/docs/api/sqlite" },
];

for (const l of demoLinks) {
  const exists = db.query("SELECT id FROM links WHERE slug = ?").get(l.slug);
  if (exists) {
    console.log(`link ${l.slug} already seeded, skipping`);
    continue;
  }
  const row = db
    .query("INSERT INTO links (slug, url, user_id) VALUES (?, ?, ?) RETURNING *")
    .get(l.slug, l.url, alice.id);
  console.log("seeded link", row);
}

console.log(`seeding complete for db=${dbPath}`);
```

