```ts
import { describe, test, expect, beforeAll, afterAll } from "bun:test";
import { createServer } from "./src/server";

let server: ReturnType<typeof createServer>;
let baseUrl: string;

beforeAll(() => {
  server = createServer(0); // L5: port 0 → OS picks a free port, no fixed-port flakiness
  baseUrl = `http://localhost:${server.port}`;
});

afterAll(() => {
  server.stop(true);
});

describe("linktrack capstone", () => {
  test("register -> login -> create link -> WS live update", async () => {
    const username = `user_${crypto.randomUUID().slice(0, 8)}`;
    const password = "s3cret-password";

    const registerRes = await fetch(`${baseUrl}/api/register`, {
      method: "POST",
      body: JSON.stringify({ username, password }),
    });
    expect(registerRes.status).toBe(201);

    const loginRes = await fetch(`${baseUrl}/api/login`, {
      method: "POST",
      body: JSON.stringify({ username, password }),
    });
    expect(loginRes.status).toBe(200);
    const { token } = await loginRes.json();
    expect(typeof token).toBe("string");

    const ws = new WebSocket(baseUrl.replace("http", "ws") + "/ws");

    await new Promise<void>((resolve, reject) => {
      ws.addEventListener("open", () => resolve());
      ws.addEventListener("error", reject);
    });

    const wsMessage = new Promise<any>((resolve, reject) => {
      const timer = setTimeout(() => reject(new Error("WS timeout")), 5000);
      ws.addEventListener("message", (event) => {
        clearTimeout(timer);
        resolve(JSON.parse(event.data as string));
      });
    });

    const linkRes = await fetch(`${baseUrl}/api/links`, {
      method: "POST",
      headers: { authorization: `Bearer ${token}` },
      body: JSON.stringify({ url: "https://example.com" }),
    });
    expect(linkRes.status).toBe(201);
    const link = await linkRes.json();

    const wsEvent = await wsMessage;
    expect(wsEvent.type).toBe("link.created");
    expect(wsEvent.slug).toBe(link.slug);

    ws.close();
  });

  test("SSE /events streams link.created", async () => {
    const res = await fetch(`${baseUrl}/events`);
    expect(res.headers.get("content-type")).toContain("text/event-stream");

    const reader = res.body!.getReader();
    const decoder = new TextDecoder();

    const first = await reader.read();
    expect(decoder.decode(first.value)).toContain("event: ping");

    const username = `sse_${crypto.randomUUID().slice(0, 8)}`;
    await fetch(`${baseUrl}/api/register`, {
      method: "POST",
      body: JSON.stringify({ username, password: "pw" }),
    });
    const loginRes = await fetch(`${baseUrl}/api/login`, {
      method: "POST",
      body: JSON.stringify({ username, password: "pw" }),
    });
    const { token } = await loginRes.json();

    const readPromise = reader.read();
    await fetch(`${baseUrl}/api/links`, {
      method: "POST",
      headers: { authorization: `Bearer ${token}` },
      body: JSON.stringify({ url: "https://bun.sh" }),
    });

    const second = await readPromise;
    expect(decoder.decode(second.value)).toContain("event: link.created");

    reader.cancel();
  });

  test("EADDRINUSE reproduced on fixed-port collision", () => {
    const fixedPort = 34567 + Math.floor(Math.random() * 1000);
    const s1 = createServer(fixedPort);
    let caughtCode: string | undefined;
    try {
      createServer(fixedPort); // Bun.serve throws SYNCHRONOUSLY, unlike Node's async 'error' event
    } catch (err: any) {
      caughtCode = err.code;
    }
    expect(caughtCode).toBe("EADDRINUSE");
    s1.stop(true);
  });
});
