## `source/auth-middleware.mjs`

```js
// auth-middleware.mjs
//
// Closes the most dangerous gap in jose's raw jwtVerify(): by default
// jwtVerify() does NOT check `aud`, does NOT check `iss`, and does NOT
// restrict `alg` unless those options are passed explicitly. A token minted
// for another service, with a spoofed issuer, or signed with an unexpected
// algorithm will pass jwtVerify(jwt, key) silently. verifyToken() and
// createVerifier() make audience/issuer/algorithms mandatory so a
// misconfigured caller fails loudly at call time instead of accepting
// cross-service tokens at verify time.

import { jwtVerify } from 'jose';

/**
 * verifyToken(jwt, key, opts)
 *
 * @param {string} jwt - compact JWS/JWT string
 * @param {import('jose').KeyLike | Uint8Array} key - verification key
 *   (e.g. the `publicKey` half of `generateKeyPair('ES256')`)
 * @param {{
 *   audience: string | string[],
 *   issuer: string | string[],
 *   algorithms: string[]
 * }} opts - all three are REQUIRED. There is no default; omitting any one
 *   throws synchronously before jwtVerify is even called.
 * @returns {Promise<import('jose').JWTVerifyResult>}
 */
export async function verifyToken(jwt, key, opts = {}) {
  const { audience, issuer, algorithms } = opts;

  if (!audience) {
    throw new Error(
      'verifyToken: opts.audience is required (jwtVerify does not enforce aud by default)'
    );
  }
  if (!issuer) {
    throw new Error(
      'verifyToken: opts.issuer is required (jwtVerify does not enforce iss by default)'
    );
  }
  if (!algorithms || algorithms.length === 0) {
    throw new Error(
      'verifyToken: opts.algorithms is required (jwtVerify accepts any alg by default)'
    );
  }

  return jwtVerify(jwt, key, { audience, issuer, algorithms });
}

/**
 * createVerifier(key, opts)
 *
 * Factory that pre-binds a verification key + {audience, issuer, algorithms}
 * once, returning a single-arg verifier `(jwt) => Promise<JWTVerifyResult>`
 * with the same enforcement guarantees as verifyToken.
 *
 * @param {import('jose').KeyLike | Uint8Array} key
 * @param {{ audience: string|string[], issuer: string|string[], algorithms: string[] }} opts
 * @returns {(jwt: string) => Promise<import('jose').JWTVerifyResult>}
 */
export function createVerifier(key, opts = {}) {
  return (jwt) => verifyToken(jwt, key, opts);
}
```

