```js
// poc.test.mjs
//
// CI-style test: proves the full accept/reject matrix using live jose
// Web Crypto operations. No mocks, no network, no disk I/O.

import test from 'node:test';
import assert from 'node:assert/strict';
import { generateKeyPair, SignJWT, jwtVerify } from 'jose';
import { verifyToken, createVerifier } from './auth-middleware.mjs';

// Built once for the whole file — generateKeyPair is in-process Web Crypto.
const { publicKey, privateKey } = await generateKeyPair('ES256', { extractable: true });

const AUDIENCE = 'my-api';
const ISSUER = 'https://auth.example.com';
const SUBJECT = 'user123';

async function signValidToken({ aud = AUDIENCE, iss = ISSUER, expOffsetSec = 3600 } = {}) {
  const now = Math.floor(Date.now() / 1000);
  return new SignJWT({})
    .setProtectedHeader({ alg: 'ES256' })
    .setSubject(SUBJECT)
    .setAudience(aud)
    .setIssuer(iss)
    .setIssuedAt(now)
    .setExpirationTime(now + expOffsetSec)
    .sign(privateKey);
}

// 1 ---------------------------------------------------------------------
test('aud NOT enforced by default: jwtVerify accepts wrong-audience token without audience option', async () => {
  const jwt = await signValidToken({ aud: 'other-service' });
  // No `audience` option passed — jwtVerify does NOT check aud, resolves fine.
  const { payload } = await jwtVerify(jwt, publicKey);
  assert.equal(payload.aud, 'other-service');
});

// 2 ---------------------------------------------------------------------
test('verifyToken enforces audience: wrong aud -> JWTClaimValidationFailed', async () => {
  const jwt = await signValidToken({ aud: 'other-service' });
  await assert.rejects(
    () => verifyToken(jwt, publicKey, { audience: AUDIENCE, issuer: ISSUER, algorithms: ['ES256'] }),
    (err) => {
      console.log(`  audience rejection: ${err.constructor.name} code=${err.code} claim=${err.claim}`);
      assert.equal(err.constructor.name, 'JWTClaimValidationFailed');
      assert.equal(err.code, 'ERR_JWT_CLAIM_VALIDATION_FAILED');
      assert.equal(err.claim, 'aud');
      return true;
    }
  );
});

// 3 ---------------------------------------------------------------------
test('verifyToken enforces issuer: wrong iss -> JWTClaimValidationFailed', async () => {
  const jwt = await signValidToken({ iss: 'https://evil.example.com' });
  await assert.rejects(
    () => verifyToken(jwt, publicKey, { audience: AUDIENCE, issuer: ISSUER, algorithms: ['ES256'] }),
    (err) => {
      console.log(`  issuer rejection: ${err.constructor.name} code=${err.code} claim=${err.claim}`);
      assert.equal(err.constructor.name, 'JWTClaimValidationFailed');
      assert.equal(err.code, 'ERR_JWT_CLAIM_VALIDATION_FAILED');
      assert.equal(err.claim, 'iss');
      return true;
    }
  );
});

// 4 ---------------------------------------------------------------------
test('verifyToken enforces algorithms: RS256 allowlist rejects ES256 token -> JOSEAlgNotAllowed', async () => {
  const jwt = await signValidToken();
  await assert.rejects(
    () => verifyToken(jwt, publicKey, { audience: AUDIENCE, issuer: ISSUER, algorithms: ['RS256'] }),
    (err) => {
      console.log(`  algorithm rejection: ${err.constructor.name} code=${err.code}`);
      assert.equal(err.constructor.name, 'JOSEAlgNotAllowed');
      assert.equal(err.code, 'ERR_JOSE_ALG_NOT_ALLOWED');
      return true;
    }
  );
});

// 5 ---------------------------------------------------------------------
test('verifyToken rejects tampered JWT -> JWSSignatureVerificationFailed', async () => {
  const jwt = await signValidToken();
  const [h, p, s] = jwt.split('.');
  // Flip one base64url-safe char in the payload segment to invalidate the signature.
  const tamperedPayload = p.slice(0, -1) + (p.slice(-1) === 'A' ? 'B' : 'A');
  const tampered = `${h}.${tamperedPayload}.${s}`;

  await assert.rejects(
    () => verifyToken(tampered, publicKey, { audience: AUDIENCE, issuer: ISSUER, algorithms: ['ES256'] }),
    (err) => {
      console.log(`  tamper rejection: ${err.constructor.name} code=${err.code}`);
      assert.equal(err.constructor.name, 'JWSSignatureVerificationFailed');
      assert.equal(err.code, 'ERR_JWS_SIGNATURE_VERIFICATION_FAILED');
      return true;
    }
  );
});

// 6 ---------------------------------------------------------------------
test('verifyToken rejects expired JWT (past exp, no sleep) -> JWTExpired', async () => {
  const jwt = await signValidToken({ expOffsetSec: -30 }); // exp already 30s in the past
  await assert.rejects(
    () => verifyToken(jwt, publicKey, { audience: AUDIENCE, issuer: ISSUER, algorithms: ['ES256'] }),
    (err) => {
      console.log(`  expiry rejection: ${err.constructor.name} code=${err.code}`);
      assert.equal(err.constructor.name, 'JWTExpired');
      assert.equal(err.code, 'ERR_JWT_EXPIRED');
      return true;
    }
  );
});

// 7 ---------------------------------------------------------------------
test('verifyToken happy path: valid token with correct aud/iss/alg -> verified payload', async () => {
  const jwt = await signValidToken();
  const { payload } = await verifyToken(jwt, publicKey, {
    audience: AUDIENCE,
    issuer: ISSUER,
    algorithms: ['ES256'],
  });
  console.log(
    `  verified payload: sub=${payload.sub} aud=${payload.aud} iss=${payload.iss} iat=${payload.iat} exp=${payload.exp}`
  );
  assert.equal(payload.sub, SUBJECT);
  assert.equal(payload.aud, AUDIENCE);
  assert.equal(payload.iss, ISSUER);
  assert.equal(typeof payload.iat, 'number');
  assert.equal(typeof payload.exp, 'number');
});

// 8 ---------------------------------------------------------------------
test('createVerifier factory: single-arg verifier rejects wrong aud and accepts correct token', async () => {
  const verify = createVerifier(publicKey, {
    audience: AUDIENCE,
    issuer: ISSUER,
    algorithms: ['ES256'],
  });

  const wrongAudJwt = await signValidToken({ aud: 'other-service' });
  let rejectedName = null;
  try {
    await verify(wrongAudJwt);
  } catch (err) {
    rejectedName = err.constructor.name;
  }

  const okJwt = await signValidToken();
  const { payload } = await verify(okJwt);

  console.log(
    `  createVerifier: rejected wrong-aud (${rejectedName}), accepted correct token (sub=${payload.sub})`
  );
  assert.equal(rejectedName, 'JWTClaimValidationFailed');
  assert.equal(payload.sub, SUBJECT);
});
```

