## `source/parse-vs-safeparse.test.mjs`

```javascript
import { test, describe } from 'node:test';
import assert from 'node:assert/strict';
import { z } from 'zod';

// --- Domain schema ---
// Field ORDER matters here: name -> age -> email.
// Zod evaluates/reports object-shape issues in schema-key order, so with a
// triple-bad input, issues[0] is deterministically the `name` issue.
const userSchema = z.object({
  name: z.string(),
  age: z.number().int().positive(),
  email: z.email(), // Zod v4 canonical top-level validator (not z.string().email())
});

const badInput = { name: 123, age: 'not-a-number', email: 'bad' };
const goodInput = { name: 'Ada Lovelace', age: 36, email: 'ada@example.com' };

describe('L0 — parse vs safeParse (Zod 4 canonical seam)', () => {
  test('safeParse(badInput) returns {success:false, error: ZodError} with issues array', () => {
    const result = userSchema.safeParse(badInput);

    assert.equal(result.success, false);
    assert.ok(result.error instanceof z.ZodError, 'error must be instanceof z.ZodError');
    assert.ok(Array.isArray(result.error.issues), 'issues must be an array');
    assert.ok(result.error.issues.length > 0, 'issues must be non-empty');
    // All three fields are wrong -> three distinct issues
    assert.equal(result.error.issues.length, 3);
  });

  test('safeParse(goodInput) returns {success:true, data}', () => {
    const result = userSchema.safeParse(goodInput);

    assert.equal(result.success, true);
    assert.deepEqual(result.data, goodInput);
  });

  test('.parse(badInput) throws ZodError', () => {
    assert.throws(
      () => userSchema.parse(badInput),
      (err) => err instanceof z.ZodError,
      'parse(badInput) must throw an instance of z.ZodError'
    );
  });

  test('ZodError.issues[0] has correct path, code, and message', () => {
    const result = userSchema.safeParse(badInput);
    const firstIssue = result.error.issues[0];

    assert.equal(firstIssue.code, 'invalid_type');
    assert.deepEqual(firstIssue.path, ['name']);
    assert.equal(firstIssue.expected, 'string');
    // Zod v4 change from v3: no `received` key on invalid_type issues
    assert.equal('received' in firstIssue, false);
    assert.equal(typeof firstIssue.message, 'string');
    assert.ok(firstIssue.message.length > 0);
  });
});
```

